const EXAMENES_2025 = [
{ex:"2025-A", n:1, area:"MED", tema:"Emergencia hipertensiva", q:"Varón de 65 años con antecedente de hipertensión arterial, acude por cefalea intensa, convulsiones y edema de papila. Examen: PA 190/120 mmHg. ¿Cuál es el medicamento inicial a usar?", o:["Labetalol","Hidralazina","Nitroprusiato","Nitroglicerina"], c:2, e:"En la encefalopatía hipertensiva (emergencia con edema de papila y convulsiones) el nitroprusiato de sodio es el clásico de elección por su inicio de acción inmediato y fácil titulación minuto a minuto."},
{ex:"2025-A", n:2, area:"GIN", tema:"Galactorrea", q:"Mujer de 32 años asintomática que acude por chequeo. Al examen de mama a la expresión de uno de los pezones sale secreción blanco lechoso. ¿Cuál es el manejo más adecuado?", o:["Solicitar prolactina","Mamografía","Ecografía de mamas","Observación"], c:0, e:"Ante galactorrea espontánea el primer paso es descartar hiperprolactinemia (fármacos, hipotiroidismo, prolactinoma) dosando prolactina sérica antes de estudios de imagen mamaria."},
{ex:"2025-A", n:3, area:"CB", tema:"Embriología - implantación", q:"¿Cuál es el sitio más frecuente de implantación del blastocisto?", o:["Fondo uterino","Segmento inferior del útero","Cérvix uterino","Cuerno uterino"], c:0, e:"El blastocisto se implanta con mayor frecuencia en la pared posterosuperior del fondo uterino, zona con mejor vascularización endometrial."},
{ex:"2025-A", n:4, area:"CIR", tema:"Trauma de tórax - tórax inestable", q:"Varón de 43 años, sufrió hace 30 minutos impacto de timón en el tórax. Presenta disnea intensa, dolor torácico izquierdo, taquipnea. PA 80/40 mmHg, FC 100X', FR 36X'; cianosis distal, movimiento paradojal de la pared torácica. RX: múltiples fracturas costales izquierdas. ¿Cuál es la conducta más adecuada?", o:["Colocación de catéter central","Ventilación no invasiva","Fijación costal quirúrgica","Intubación orotraqueal"], c:3, e:"El tórax inestable con inestabilidad hemodinámica y cianosis requiere manejo agresivo de la vía aérea: intubación orotraqueal con ventilación a presión positiva, que además estabiliza internamente el segmento inestable."},
{ex:"2025-A", n:5, area:"MED", tema:"Pares craneales - III par", q:"Varón de 27 años, acude por visión doble y caída del párpado derecho. Examen: pupila derecha dilatada con incapacidad para mover el ojo hacia el lado nasal. ¿Cuál es el par craneal comprometido?", o:["VI","I","III","IV"], c:2, e:"Ptosis + midriasis + limitación de la aducción (mirada nasal) es la tríada clásica de parálisis del III par (oculomotor), que inerva el recto medial y el elevador del párpado, además de las fibras parasimpáticas pupilares."},
{ex:"2025-A", n:6, area:"CIR", tema:"Pielonefritis complicada", q:"Mujer de 58 años con litiasis renal recurrente, presenta fiebre 39.2°C, vómitos y dolor lumbar izquierdo de 48 horas. PA 90/60 mmHg, FC 120X'. Leucocitosis. TC: litiasis obstructiva en uréter proximal izquierdo, dilatación pielocalicial y absceso perinéfrico. ¿Cuál es la intervención inicial más adecuada?", o:["Litotricia extracorpórea y seguimiento con antibióticos","Derivación urinaria urgente con catéter doble J y nefrostomía percutánea","Antibióticos de amplio espectro y nefrectomía diferida","Drenaje quirúrgico del absceso sin derivación urinaria"], c:1, e:"La pielonefritis obstructiva con absceso es una urgencia urológica: se requiere descomprimir la vía urinaria (doble J o nefrostomía) además de drenar la colección, junto con antibioticoterapia."},
{ex:"2025-A", n:7, area:"PED", tema:"Tuberculosis - infección latente", q:"Preescolar de 4 años, contacto de familiar con TB pulmonar, acude a control con PPD de 12 mm. Asintomático. Inmunizaciones completas. Examen físico normal. Rx de tórax sin hallazgos. ¿Cuál es el diagnóstico?", o:["Reacción cruzada a BCG","Infección por Mycobacterium tuberculosis","Enfermedad por Mycobacterium tuberculosis","Exposición a Mycobacterium tuberculosis"], c:1, e:"PPD positivo + Rx normal + asintomático = infección tuberculosa latente (el bacilo está presente pero controlado por el sistema inmune, sin enfermedad activa). Se indica terapia preventiva."},
{ex:"2025-A", n:8, area:"CB", tema:"Fisiología respiratoria - quimiorreceptores", q:"Varón de 64 años con EPOC, ingresa por descompensación. FR 32X'. pH 7.24, PaCO2 62 mmHg, PaO2 55 mmHg. ¿Qué tipo de receptores son los más sensibles a los cambios de CO2?", o:["Quimiorreceptores centrales del bulbo raquídeo","Receptores J (yuxtacapilares)","Receptores de estiramiento pulmonar","Quimiorreceptores periféricos carotídeos y aórticos"], c:0, e:"Los quimiorreceptores centrales bulbares son los más sensibles a cambios de PaCO2/pH del LCR y son el principal estímulo fisiológico de la ventilación en condiciones normales."},
{ex:"2025-A", n:9, area:"MED", tema:"Leptospirosis", q:"Varón de 38 años, gasfitero, presenta fiebre, escalofríos, cefalea frontal, náusea, vómitos, dolor abdominal, congestión conjuntival, mialgia intensa y fotofobia. Examen: febril, ictérico, congestión conjuntival y faríngea, mialgias, meningismo, hepatoesplenomegalia. ¿Cuál es el tratamiento indicado?", o:["Gentamicina","Sulfametoxazol","Penicilina","Metronidazol"], c:2, e:"El cuadro (ocupación de riesgo por contacto con agua contaminada, mialgias intensas, congestión conjuntival, ictericia) es leptospirosis; el tratamiento de elección en casos graves es penicilina G endovenosa."},
{ex:"2025-A", n:10, area:"CIR", tema:"Trauma abdominal por arma de fuego", q:"Varón de 46 años, hace una hora sufre impacto de proyectil de arma de fuego en abdomen. PA 60/40 mmHg, FC 100X'. Pálido. Abdomen distendido, orificio en mesogastrio, RHA disminuidos, rebote (+). ¿Cuál es la indicación inmediata?", o:["Laparotomía exploratoria","Laparoscopía diagnóstica","Exploración de la herida","FAST"], c:0, e:"Herida por arma de fuego en abdomen con inestabilidad hemodinámica y signos peritoneales es indicación absoluta de laparotomía exploratoria inmediata, sin retrasar por estudios de imagen."},
{ex:"2025-A", n:11, area:"CIR", tema:"Gangrena de Fournier", q:"Varón de 45 años, obeso y diabético no controlado, acude por gangrena de Fournier. Región anorectal: celulitis con edema y necrosis marcada con afectación del esfínter anal externo. ¿Qué tipo de colostomía es la más indicada?", o:["En caño de escopeta","Bocas separadas por piel","En asa derecha","En asa izquierda"], c:3, e:"Ante compromiso del esfínter anal en gangrena de Fournier se realiza una colostomía derivativa en asa a nivel del sigmoides (lado izquierdo del colon), que además es técnicamente más simple y reversible."},
{ex:"2025-A", n:12, area:"MED", tema:"EPOC exacerbado", q:"Varón de 74 años con EPOC moderado, acude por disnea marcada, tos con esputo mucoso y tendencia a la somnolencia. SatO2 87%, FiO2 21%; pH 7.29, PCO2 55 mmHg, PO2 62 mmHg. ¿Cuál es el hallazgo más importante para manejo intrahospitalario?", o:["Acidosis respiratoria","Neumonía atípica","Delirio hiperactivo","Insuficiencia cardíaca"], c:0, e:"El pH 7.29 con PCO2 55 confirma acidosis respiratoria aguda (falla ventilatoria tipo II), el hallazgo que determina la necesidad de hospitalización y posible ventilación no invasiva."},
{ex:"2025-A", n:13, area:"CIR", tema:"Íleo postoperatorio", q:"Varón de 25 años post laparotomía por apendicitis complicada y peritonitis generalizada; al cuarto día presenta distensión abdominal, náusea y vómitos. Abdomen distendido y doloroso, RHA ausentes, SNG 1000 ml de líquido verdoso. Electrolitos normales. ¿Cuál es el diagnóstico más probable?", o:["Perforación intestinal","Obstrucción por bridas","Íleo paralítico","Síndrome de Ogilvie"], c:2, e:"En el postoperatorio temprano de una cirugía abdominal complicada, la distensión con RHA ausentes (silencio abdominal) y sin causa mecánica es típica de íleo paralítico postoperatorio."},
{ex:"2025-A", n:14, area:"PED", tema:"Anemia - suplementación de hierro", q:"Según la norma técnica peruana para el manejo de la anemia en lactantes, si la suspensión del suplemento de hierro es mayor a 3 meses, debe...", o:["continuar el tratamiento hasta los dos años","continuar el tratamiento por 6 meses","reiniciar la indicación hasta completar el esquema previamente indicado","iniciar un nuevo esquema, previa evaluación de hemoglobina"], c:2, e:"Según la NTS de anemia del MINSA, si la interrupción del hierro supera los 3 meses se debe reiniciar el esquema hasta completar el tratamiento previamente indicado."},
{ex:"2025-A", n:15, area:"MED", tema:"Meningitis bacteriana - Listeria", q:"Varón de 80 años, hace 2 semanas presenta cefalea, náusea, vómito y luego somnolencia y convulsiones. TC: atrofia cortical. Punción lumbar: leucocitos 200/µL, hipoglucorraquia y bacilos gram positivos. ¿Cuál es el tratamiento de elección?", o:["Oxacilina","Ceftriaxona","Ampicilina","Aciclovir"], c:2, e:"Bacilos gram positivos en LCR de un adulto mayor orientan a Listeria monocytogenes, intrínsecamente resistente a cefalosporinas; el tratamiento de elección es ampicilina (± gentamicina)."},
{ex:"2025-A", n:16, area:"GIN", tema:"Tamizaje de cáncer de cérvix", q:"Mujer de 21 años, solicita información sobre screening para cáncer de cuello uterino y no manifiesta sus antecedentes sexuales. ¿Cuál es la indicación?", o:["Observación","Test de Cobas","Prueba conjunta","Citología cervical"], c:3, e:"En mujeres jóvenes (<25-30 años) el tamizaje inicial recomendado es la citología cervical (Papanicolaou); las pruebas de VPH se priorizan en mujeres mayores."},
{ex:"2025-A", n:17, area:"GIN", tema:"Restricción de crecimiento intrauterino", q:"Primigesta de 32 semanas, acude a control prenatal asintomática. AU 27 cm. Ecografía: gestación única activa con ponderado fetal en percentil 2 y doppler fetal normal. ¿Cuál es el diagnóstico más probable?", o:["Error en la edad gestacional","Restricción en el crecimiento intrauterino","Crecimiento adecuado para la edad gestacional","Pequeño para la edad gestacional"], c:1, e:"Un ponderado fetal en percentil 2 (menor al percentil 3) define restricción de crecimiento intrauterino, independientemente del doppler, por su gravedad (percentil <3)."},
{ex:"2025-A", n:18, area:"MED", tema:"Taquiarritmia por cocaína", q:"Mujer de 42 años, acude por dolor torácico y palpitaciones luego de consumo de cocaína. PA 110/70 mmHg, FC 135X', SatO2 97%. ¿Cuál es el diagnóstico más probable?", o:["Taquicardia nodal","Taquicardia supraventricular","Taquicardia sinusal","Taquicardia auricular"], c:2, e:"La cocaína produce estimulación simpática masiva; la taquicardia sinusal es la arritmia más frecuente asociada a su consumo agudo."},
{ex:"2025-A", n:19, area:"GIN", tema:"Espectro de acretismo placentario", q:"Tercigesta de 33 semanas, cesareada anterior dos veces, acude por sangrado vaginal indoloro. Ecografía: placenta cubre la totalidad del OCI con lagunas vasculares, adelgazamiento del miometrio retroplacentario y vasos puente. ¿Cuál es el diagnóstico más probable?", o:["Rotura uterina","Espectro de acretismo placentario","Hematoma retroplacentario","Rotura de vasa previa"], c:1, e:"Placenta previa + 2 cesáreas previas + lagunas vasculares + adelgazamiento miometrial son los signos ecográficos clásicos del espectro de acretismo placentario (placenta accreta)."},
{ex:"2025-A", n:20, area:"MED", tema:"Neurocisticercosis", q:"Mujer de 38 años, acude por cefalea y convulsiones tónico clónicas generalizadas de larga data. RM: dos quistes parenquimatosos compatibles con neurocisticercosis. ¿Cuál es el tratamiento de elección?", o:["Albendazol y Praziquantel","Praziquantel","Prednisona","Albendazol"], c:3, e:"Para neurocisticercosis parenquimatosa con pocas lesiones (1-2 quistes), el albendazol en monoterapia es el tratamiento antiparasitario de elección, asociado a corticoide y anticonvulsivante."},
{ex:"2025-A", n:21, area:"MED", tema:"Trastorno de pánico", q:"Mujer de 19 años, acude por sensación de miedo, sudoración, palpitaciones, dolor torácico y sensación de temor; desde hace más de un mes presenta estos episodios recurrentes. ¿Cuál es el trastorno más probable?", o:["De ansiedad generalizada","De angustia","Obsesivo compulsivo","Fóbico"], c:1, e:"Episodios recurrentes de síntomas autonómicos agudos con miedo intenso (crisis) definen el trastorno de pánico (trastorno de angustia)."},
{ex:"2025-A", n:22, area:"GIN", tema:"Isoinmunización Rh - profilaxis anti-D", q:"Primípara de 32 años, Rh negativo, puérpera de 96 horas de parto vaginal; su hijo es Rh positivo y ella no recibió inmunoglobulina anti-D durante el embarazo ni en el puerperio inmediato. ¿Cuál es la conducta a seguir?", o:["Diferir inmunoglobulina anti-D hasta el próximo embarazo","Administrar corticoides intramuscular","Solicitar prueba de coombs indirecta","Colocar inmunoglobulina anti-D inmediatamente"], c:3, e:"Aunque lo ideal es aplicar la anti-D dentro de las 72 horas postparto, se recomienda administrarla igualmente lo antes posible si se pasó ese plazo, ya que aún puede aportar algo de protección."},
{ex:"2025-A", n:23, area:"CIR", tema:"Cáncer gástrico", q:"Varón de 70 años, hace 8 meses presenta dolor epigástrico constante, llenura precoz y melena. Examen: adenopatía supraclavicular izquierda, masa dolorosa en epigastrio. Hb 8 g/dL. ¿Cuál es el diagnóstico más probable?", o:["NM gástrico","Úlcera duodenal","Linfoma gástrico","Tumor de Pancoast"], c:0, e:"La adenopatía supraclavicular izquierda (ganglio de Virchow) junto con síntomas constitucionales y masa epigástrica es un signo clásico de cáncer gástrico avanzado."},
{ex:"2025-A", n:24, area:"MED", tema:"Pares craneales - IX par", q:"Varón de 14 años post amigdalectomizado presenta alteración del gusto. Examen: ageusia en el tercio posterior de la lengua, anestesia de la faringe, sequedad oral parcial y dificultad en la deglución. ¿Qué par craneal se encuentra comprometido?", o:["IX","VII","XI","XII"], c:0, e:"El glosofaríngeo (IX par) da la sensibilidad gustativa y general del tercio posterior de la lengua y la faringe; su lesión post-quirúrgica explica ageusia posterior, anestesia faríngea y disfagia."},
{ex:"2025-A", n:25, area:"PED", tema:"Infección urinaria febril del lactante", q:"Lactante de 9 meses, desde hace 3 días presenta fiebre y vómitos frecuentes. T° 39°C. Leucocitos 20,000/µL, abastonados 700/µL; examen de orina: nitrito positivo y 100 leucocitos/campo. ¿Cuál es la conducta más adecuada?", o:["Hospitalizar para hidratación y antibioticoterapia parenteral","Iniciar hidratación por vía oral e indicar antibioticoterapia oral","Administrar antibioticoterapia parenteral","Realizar ecografía renal para descartar absceso"], c:0, e:"La ITU febril en un lactante menor de 12 meses con signos de mal estado (vómitos, no tolera vía oral) se maneja hospitalizado con antibioticoterapia e hidratación parenteral."},
{ex:"2025-A", n:26, area:"SP", tema:"Salud ambiental - intoxicación por plomo", q:"Desde hace tres años, un centro de salud en una comunidad minera ha incrementado la notificación de casos de menores de diez años con retardo del desarrollo psicomotor, irritabilidad, cefalea, vómitos y disgeusia. ¿Qué contaminante ambiental es la causa más probable?", o:["Azufre","Arsénico","Plomo","Níquel"], c:2, e:"En zonas de minería, el retardo del desarrollo psicomotor con irritabilidad y síntomas neurológicos en niños es el cuadro clásico de intoxicación crónica por plomo."},
{ex:"2025-A", n:27, area:"MED", tema:"Anemia de enfermedad crónica", q:"Varón de 36 años con astenia y fatigabilidad. Palidez de piel y mucosa. Laboratorio: anemia normocítica normocrómica, hierro sérico disminuido, saturación de transferrina baja y ferritina aumentada. ¿Cuál es el mecanismo fisiopatológico de la anemia?", o:["Disminución de la respuesta eritropoyética","Secuestro de hierro en los macrófagos","Producción inadecuada de transferrina","Aumento de la hepcidina"], c:3, e:"En la anemia de enfermedad crónica/inflamatoria, la citoquina hepcidina está elevada y bloquea la ferroportina, atrapando el hierro dentro de los macrófagos (ferritina alta, hierro sérico bajo)."},
{ex:"2025-A", n:28, area:"PED", tema:"Intoxicación alimentaria", q:"Adolescente de 14 años, acude por náusea, vómitos y deposiciones líquidas sin moco sin sangre. Compañeros con síntomas similares tras comer hamburguesa en una excursión. ¿Cuál es el probable agente infeccioso?", o:["Bacillus cereus","Vibrion cholerae","Staphylococcus aureus","Campylobacter jejuni"], c:2, e:"El inicio rápido de vómitos tras consumo de alimentos manipulados (carnes) en un grupo, con síntomas simultáneos, sugiere intoxicación por toxina preformada de Staphylococcus aureus."},
{ex:"2025-A", n:29, area:"MED", tema:"Intoxicación por monóxido de carbono", q:"Obrero de 30 años rescatado de un incendio; presenta estridor laríngeo, tos y dificultad respiratoria. La oximetría muestra SatO2 90%, pero la gasometría arterial revela PaO2 normal. ¿Cuál es la causa de estos hallazgos?", o:["Reduce la capacidad de hemoglobina para captar oxígeno por modificación en su estructura","Se disuelve pobremente en el plasma sanguíneo reduciendo el oxígeno disuelto","Se une a la hemoglobina formando carboxihemoglobina","Interfiere con la liberación de oxígeno de la hemoglobina a los tejidos"], c:2, e:"El CO se une a la hemoglobina con mucha mayor afinidad que el O2, formando carboxihemoglobina; el PaO2 disuelto es normal pero el transporte de oxígeno está gravemente reducido (la pulsioximetría estándar puede sobreestimar la SatO2 real)."},
{ex:"2025-A", n:30, area:"PED", tema:"Neumonía atípica", q:"Niño de 10 años, hace 5 días rinorrea acuosa y disfagia, 2 días antes tos con flema, sibilancias, fiebre e hiporexia. Tórax: sibilantes y subcrépitos difusos, tirajes. Leucocitos 12,000/µL; PCR 5 mg/L; procalcitonina ligeramente elevada. ¿Cuál es el agente etiológico más probable?", o:["Streptococcus pneumoniae","Haemophilus influenzae tipo b","Virus sincitial respiratorio","Mycoplasma pneumoniae"], c:3, e:"En escolares, el inicio subagudo con síntomas catarrales prolongados, sibilancias y marcadores inflamatorios solo levemente elevados es típico de neumonía atípica por Mycoplasma pneumoniae."},
{ex:"2025-A", n:31, area:"MED", tema:"Sepsis urinaria por BLEE", q:"Varón de 75 años, procedente de residencia de ancianos, sepsis de origen urinario. Hemocultivos y urocultivo: E. coli productora de betalactamasas de espectro ampliado; antibiograma pendiente. ¿Cuál es el antibiótico mejor indicado?", o:["Aztreonam","Ertapenem","Cefotaxima","Ceftriaxona"], c:1, e:"Para infecciones graves por enterobacterias productoras de BLEE, los carbapenémicos son el tratamiento de elección; ertapenem cubre bien BLEE sin necesidad de cobertura antipseudomónica."},
{ex:"2025-A", n:32, area:"CIR", tema:"Hernia inguinal estrangulada", q:"Varón de 40 años, hace un día con dolor inguinal izquierdo tras levantar objeto pesado. Tumoración 2x2 cm indurada, no reductible, con signos de flogosis. Rx: múltiples niveles hidroaéreos. ¿Cuál es el diagnóstico?", o:["Hernia de Spiegel estrangulada","Hernia crural encarcelada","Hernia inguinal estrangulada","Íleo adinámico"], c:2, e:"Tumoración inguinal no reductible con flogosis y niveles hidroaéreos (obstrucción intestinal) tras esfuerzo indica hernia inguinal estrangulada, urgencia quirúrgica."},
{ex:"2025-A", n:33, area:"GIN", tema:"Presentación de cara", q:"Multigesta de 40 semanas, dilatación 9 cm, borramiento 100%, membranas rotas con líquido claro, se palpa presentación de cara mento anterior. ¿Cuál es la conducta más adecuada?", o:["Programar cesárea de emergencia","Usar vacuum de salida","Convertir a presentación occipucio","Dejar evolucionar parto vaginal"], c:3, e:"La presentación de cara mento-anterior (a diferencia de la mento-posterior) permite el parto vaginal porque el mentón puede rotar bajo la sínfisis; se deja evolucionar el trabajo de parto."},
{ex:"2025-A", n:34, area:"MED", tema:"Hemorragia digestiva alta - omeprazol", q:"Mujer de 45 años, usuaria crónica de AINES, acude por hematemesis y melena activa. PA 80/50 mmHg. Luego de bolo de omeprazol se decide continuar infusión. ¿Cuál es la velocidad de infusión del omeprazol en mg/h?", o:["8","6","4","10"], c:0, e:"Tras el bolo inicial de IBP en HDA por úlcera de alto riesgo, la infusión continua estándar es de 8 mg/hora durante 72 horas."},
{ex:"2025-A", n:35, area:"CB", tema:"Fisiología endocrina - glucagón", q:"¿Cuál es la hormona responsable de aumentar la producción hepática de glucosa durante un ayuno prolongado de 24 horas?", o:["Glucagon","Insulina","Leptina","Somatostatina"], c:0, e:"El glucagón estimula la glucogenólisis y gluconeogénesis hepáticas para mantener la glucemia durante el ayuno prolongado."},
{ex:"2025-A", n:36, area:"MED", tema:"IAM con elevación del ST", q:"Mujer de 47 años, hipertensa mal controlada, hace 20 minutos dolor precordial opresivo irradiado a brazo izquierdo. EKG: supradesnivel del ST en todas las derivadas precordiales. En un escenario ideal, ¿cuál es el tratamiento de elección?", o:["Oxigenoterapia","Fibrinolisis","Doble antiagregación","Intervención coronaria"], c:3, e:"En un IAM con elevación del ST extenso, si se dispone de sala de hemodinamia en tiempo adecuado (escenario ideal), la angioplastia primaria (intervención coronaria percutánea) es superior a la fibrinolisis."},
{ex:"2025-A", n:37, area:"MED", tema:"Intoxicación por valproato", q:"Mujer de 32 años con ataxia y temblor de manos. Antecedente de epilepsia tratada con fármaco que aumenta los niveles de GABA. Examen: petequias. Laboratorio: hiperamonemia. ¿Qué medicamento se ha utilizado?", o:["Etosuximida","Gabapentina","Fenitoína","Valproato"], c:3, e:"La combinación de ataxia, trombocitopenia (petequias) e hiperamonemia es característica de toxicidad por ácido valproico."},
{ex:"2025-A", n:38, area:"MED", tema:"Hiperparatiroidismo primario", q:"Varón de 39 años, obeso, acude por anorexia, constipación, poliuria y dolores óseos difusos. Laboratorio: calcio 11.6 mg/dL. ¿Cuál es el diagnóstico presuntivo?", o:["Consumo de tiazidas","Hiperparatiroidismo primario","Neoplasia metastásica","Hiperparatiroidismo secundario"], c:1, e:"Hipercalcemia con síntomas óseos, gastrointestinales y renales ('huesos, gemidos abdominales, quejidos psíquicos, cálculos') en ausencia de otra causa evidente orienta a hiperparatiroidismo primario."},
{ex:"2025-A", n:39, area:"MED", tema:"Acromegalia", q:"En pacientes con acromegalia secundaria a adenomas que secretan GH, ¿cuál es el tratamiento inicial?", o:["Pegvisomant","Cabergolina","Octeótride","Ablación quirúrgica"], c:3, e:"El tratamiento de primera línea de la acromegalia por adenoma hipofisario es la cirugía transesfenoidal (ablación quirúrgica); el tratamiento médico se reserva para casos residuales o no candidatos a cirugía."},
{ex:"2025-A", n:40, area:"GIN", tema:"Embarazo postérmino", q:"Primigesta de 41 semanas, aún sin trabajo de parto. Tacto vaginal desfavorable. Ecografía: ponderado fetal 3700 g y oligohidramnios. Test no estresante normal. ¿Cuál es la conducta más adecuada?", o:["Inducción de trabajo de parto","Cesárea a las 42 semanas","Vigilancia fetal cada 72 horas","Cesárea de emergencia"], c:0, e:"El embarazo postérmino con oligohidramnios es indicación de finalizar la gestación; con bienestar fetal actual (NST normal) se prefiere la inducción del parto en vez de esperar hasta las 42 semanas."},
{ex:"2025-A", n:41, area:"CIR", tema:"Tumor carcinoide apendicular", q:"Mujer de 30 años, durante apendicectomía se encuentra una tumoración menor de 2 cm en la punta del apéndice, sin extensión extraapendicular. ¿Cuál es la conducta indicada?", o:["Colectomía ascendente","Ileostomía","Hemicolectomía derecha","Apendicectomía"], c:3, e:"Un tumor carcinoide apendicular menor de 2 cm, localizado en la punta y sin invasión, se trata adecuadamente con apendicectomía simple; la hemicolectomía se reserva para tumores >2 cm o con invasión de la base/mesoapéndice."},
{ex:"2025-A", n:42, area:"CB", tema:"Anatomía - plexo braquial", q:"Varón de 18 años sufre caída sobre su hombro izquierdo. Examen: hombro en aducción, brazo en rotación interna y codo extendido ('mano de propina'). ¿Dónde se localiza la lesión?", o:["Tronco inferior del plexo braquial","Nervio cubital y braquial cutáneo medial","Tronco superior del plexo braquial","Tronco medio del plexo braquial"], c:2, e:"La postura en 'mano de propina del mesero' (aducción, rotación interna, codo extendido) es la parálisis de Erb-Duchenne, por lesión del tronco superior del plexo braquial (raíces C5-C6)."},
{ex:"2025-A", n:43, area:"GIN", tema:"Sistema POP-Q", q:"En el sistema de cuantificación POP-Q para prolapso genital, ¿qué significa cuando el punto D se omite?", o:["Dificultad para cuantificar","Prolapso genital total","Hay presencia de incontinencia","No hay cérvix"], c:3, e:"El punto D representa el fondo de saco posterior (relacionado al cérvix); se omite cuando la paciente ha sido histerectomizada y no tiene cérvix."},
{ex:"2025-A", n:44, area:"MED", tema:"Osteomielitis vertebral", q:"Mujer de 65 años, diabética con ERC en diálisis hace 4 años, desde hace un mes dorsalgia y fiebre; en la última semana debilidad en miembros inferiores y dificultad para la micción. ¿Cuál es el diagnóstico más probable?", o:["Metástasis ósea","Osteomielitis vertebral","Espóndiloartrosis","Paraparesia espástica"], c:1, e:"Dorsalgia + fiebre + déficit neurológico progresivo en un paciente con accesos vasculares (diálisis, riesgo de bacteriemia) es muy sugerente de osteomielitis vertebral con posible absceso epidural compresivo."},
{ex:"2025-A", n:45, area:"CIR", tema:"Diverticulitis aguda complicada", q:"Mujer de 75 años, desde hace 4 días dolor abdominal en fosa iliaca izquierda, vómitos, alza térmica y rectorragia. Antecedente de estreñimiento crónico. Abdomen distendido, RHA ausentes, rebote (+); TR: sangre. ¿Cuál es el diagnóstico más probable?", o:["Colitis infecciosa","Apendicitis aguda","Diverticulitis aguda","Enfermedad de Crohn"], c:2, e:"Dolor en fosa iliaca izquierda con fiebre, signos peritoneales y sangrado en una paciente con estreñimiento crónico (factor de riesgo de diverticulosis) es el cuadro clásico de diverticulitis aguda complicada."},
{ex:"2025-A", n:46, area:"CB", tema:"Fisiología - absorción de hierro", q:"¿Qué sustancia facilita la absorción de hierro a nivel intestinal?", o:["Polifenoles","Calcio","Fructosa","Oxalatos"], c:2, e:"A diferencia de polifenoles, calcio y oxalatos (que inhiben la absorción de hierro no-hemo), la fructosa (como la vitamina C) favorece su absorción al mantenerlo en forma reducida (Fe2+)."},
{ex:"2025-A", n:47, area:"SP", tema:"Niveles de prevención - promoción", q:"Con el objetivo de disminuir la incidencia de embarazo en adolescentes, la Dirección Regional de Salud implementa un plan de comunicación educativa dirigido a escolares de secundaria. ¿Qué tipo de intervención sanitaria se está implementando?", o:["Rehabilitación","Prevención","Promoción","Recuperación"], c:2, e:"Las intervenciones educativas dirigidas a modificar conductas y empoderar a la población (sin actuar sobre un factor de riesgo específico ya identificado) corresponden a promoción de la salud."},
{ex:"2025-A", n:48, area:"GIN", tema:"Enfermedad pélvica inflamatoria", q:"Mujer de 32 años, dolor en fosa iliaca derecha de tres días, progresivo. Antecedente de hidrosonografía hace 10 días. Dolor a la movilización de cérvix, flujo vaginal con mal olor. Eco TV: útero de 7 cm, líquido en fondo de saco. ¿Cuál es el manejo más adecuado?", o:["Clindamicina + gentamicina","Doxiciclina + ceftriaxona + metronidazol","Doxiciclina + azitromicina","Ceftriaxona + doxiciclina + gentamicina"], c:1, e:"El dolor a la movilización cervical con flujo fétido y líquido libre es enfermedad pélvica inflamatoria; el esquema estándar cubre gonococo, clamidia y anaerobios: ceftriaxona + doxiciclina + metronidazol."},
{ex:"2025-A", n:49, area:"MED", tema:"Primera crisis convulsiva", q:"Varón de 32 años, pérdida de conciencia brusca con movimientos tónico clónicos generalizados; refiere 2 días sin dormir por estrés, nunca tuvo un cuadro similar. Post ictal, mordedura de lengua. ¿Cuál es la indicación?", o:["Fenitoina","Conducta expectante","Fenobarbital","Valproato de sodio"], c:1, e:"Ante una primera crisis convulsiva no provocada, con un factor precipitante claro (privación de sueño) y recuperación completa, la conducta es expectante con estudio ambulatorio, sin iniciar antiepilépticos de inmediato."},
{ex:"2025-A", n:50, area:"GIN", tema:"VIH en gestante - vía de parto", q:"Primigesta de 37 semanas, sin controles prenatales, dolor tipo contracción esporádico. Laboratorio: VIH positivo y carga viral en 2000 copias/mL. ¿Cuál es la conducta más adecuada para la vía de parto?", o:["Parto vaginal espontaneo","Cesárea programada","Inducción a las 39 semanas","Parto instrumentado"], c:1, e:"Con carga viral mayor a 1000 copias/mL cerca del término, se indica cesárea programada para reducir el riesgo de transmisión vertical del VIH."},
{ex:"2025-A", n:51, area:"PED", tema:"Onfalitis", q:"Recién nacido de 6 días, presenta enrojecimiento, calor local, secreción purulenta y mal olor en la base del cordón umbilical, pobre succión y sueño incrementado. Eritema periumbilical de 2 cm con induración; succión irregular e hipoactividad. ¿Cuál es la conducta más adecuada?", o:["Administrar antibióticos tópicos y seguimiento ambulatorio estrecho","Iniciar tratamiento antibiótico intramuscular y evaluar en 48 horas","Realizar hemocultivo y esperar resultados para iniciar antibioticoterapia","Hospitalizar al neonato e iniciar tratamiento antibiótico intravenoso de amplio espectro"], c:3, e:"La onfalitis con eritema >2 cm más signos sistémicos (hipoactividad, pobre succión) en un neonato requiere hospitalización y antibioticoterapia intravenosa de amplio espectro por el riesgo de sepsis."},
{ex:"2025-A", n:52, area:"PED", tema:"Anemia del prematuro", q:"Recién nacido prematuro de 28 semanas y 1050 g en UCIN; requirió múltiples extracciones sanguíneas. A los 10 días, Hb 8.0 g/dL. ¿Qué medida inicial tiene mayor impacto en disminuir la probabilidad de requerir una transfusión?", o:["Administrar eritropoyetina para estimular la producción de glóbulos rojos","Iniciar suplementación con hierro intravenoso","Restringir toma de muestras de sangre para exámenes de laboratorio","Considerar la transfusión inmediata para corregir la anemia sintomática"], c:2, e:"La causa principal de anemia en el prematuro hospitalizado es la pérdida iatrogénica por flebotomías repetidas; restringir las extracciones es la medida de mayor impacto preventivo."},
{ex:"2025-A", n:53, area:"PED", tema:"Asma - manejo agudo", q:"Niño de 2 años, tos seca nocturna hace 2 días. Antecedente de bronquiolitis y síndrome obstructivo bronquial recurrente; hermano asmático, mascotas en casa. Examen: taquipnea, tirajes, sibilantes espiratorios difusos. ¿Cuál es la acción inicial más apropiada?", o:["Solicitar Rx de tórax urgente","Administrar corticoides sistémicos","Administrar broncodilatadores","Administrar antileucotrienos"], c:2, e:"Ante una crisis de sibilancias con dificultad respiratoria, el primer paso siempre es el broncodilatador de acción corta (salbutamol), independientemente de si se agregan luego corticoides."},
{ex:"2025-A", n:54, area:"MED", tema:"Angina estable", q:"Varón de 54 años, hipertenso y fumador, dolor torácico opresivo retroesternal que aumenta con el esfuerzo y mejora con el reposo, irradiado a brazo y mandíbula. Antecedente familiar de IAM en padre a los 54 años. ¿Cuál es la conducta inicial a seguir?", o:["Realizar electrocardiograma","Solicitar péptido natriurético","Programar ergometría","Realizar angiotem"], c:0, e:"Ante todo dolor torácico sugestivo de origen cardiaco, el primer paso siempre es el electrocardiograma de 12 derivaciones."},
{ex:"2025-A", n:55, area:"PED", tema:"Riesgo de sepsis neonatal", q:"Neonato pretérmino tardío, ruptura de membranas de 20 h, líquido amniótico claro, peso 2700 g, APGAR 9-10 y buen reflejo de succión. ¿Cuál es la conducta más apropiada?", o:["Monitorizar signos de infección","Solicitar ecocardiografía","Estudio de LCR","Iniciar antibióticos de amplio espectro"], c:0, e:"Con ruptura de membranas prolongada pero sin otros factores de riesgo y un recién nacido asintomático y vigoroso, la conducta es observación clínica estrecha para signos de infección, sin antibióticos empíricos de entrada."},
{ex:"2025-A", n:56, area:"CIR", tema:"Fístula colovesical", q:"Varón de 70 años, con diabetes mellitus y enfermedad diverticular, dolor abdominal recurrente en cuadrante inferior izquierdo, fiebre, neumaturia y fecaluria. ¿Cuál es la complicación más probable?", o:["Fístula colovesical","Absceso pélvico","Obstrucción colónica","Infección urinaria"], c:0, e:"Neumaturia y fecaluria son patognomónicos de fístula colovesical, complicación clásica de la diverticulitis crónica/recurrente."},
{ex:"2025-A", n:57, area:"MED", tema:"Síndrome del seno enfermo", q:"Varón de 35 años, diagnóstico de síndrome de taqui-bradi por estudios electrofisiológicos; tras tratamiento médico, ingresa por palpitaciones y síncopes. ¿Cuál es la mejor indicación?", o:["Marcapaso","Carvedilol","Atropina","Ablación"], c:0, e:"El síndrome de taqui-bradicardia (disfunción del nodo sinusal) sintomático y refractario a tratamiento médico requiere implante de marcapaso definitivo."},
{ex:"2025-A", n:58, area:"GIN", tema:"Endometrioma / endometriosis", q:"Mujer de 35 años, dismenorrea y dolor a la defecación desde hace un año. Ecografía: tumor quístico anexial 'en vidrio esmerilado' de 3 cm. El tratamiento de primera opción además de analgésicos incluye:", o:["Agonista de la GnRH","Antagonista de la GnRH","Anticonceptivos combinados","Progesterona"], c:2, e:"El endometrioma con dolor asociado a endometriosis se maneja de primera línea con anticonceptivos orales combinados (junto con AINEs), reservando los análogos de GnRH para casos refractarios."},
{ex:"2025-A", n:59, area:"PED", tema:"Dengue grave", q:"Niño de 10 años, desde hace 3 días ictericia, letargo, somnolencia y hematemesis; 7 días antes fiebre, dolor abdominal y vómitos que cedieron. Ictericia, hígado a 3 cm doloroso. Glasgow 12, ROT aumentados. Según su presunción diagnóstica, ¿cuál es la conducta inicial?", o:["Hidratación parenteral y referencia a centro hospitalario de mayor complejidad","Iniciar tratamiento empírico con antibióticos de amplio espectro","Administrar omeprazol y mantener en observación","Solicitar pruebas de función hepática y ecografía abdominal"], c:0, e:"El cuadro sugiere dengue grave con compromiso hepático y hemorragia digestiva (fase crítica tardía); requiere estabilización con hidratación parenteral y referencia inmediata a mayor nivel de complejidad."},
{ex:"2025-A", n:60, area:"CB", tema:"Fisiología renal - IECA/ARA-II", q:"¿Qué efecto inmediato se espera en la filtración glomerular al administrar un fármaco que inhiba la angiotensina II?", o:["Aumento de la presión oncótica capilar","Aumento por vasoconstricción de la arteriola eferente","Sin cambios, la TFG depende de la presión hidrostática","Disminución por vasodilatación de la arteriola eferente"], c:3, e:"La angiotensina II mantiene el tono de la arteriola eferente; al bloquearla (IECA/ARA-II) esta se dilata, cae la presión de filtración y disminuye la TFG de forma aguda."},
{ex:"2025-A", n:61, area:"PED", tema:"Conjuntivitis neonatal", q:"La conjuntivitis neonatal es una infección ocular que puede tener graves consecuencias para el recién nacido. ¿Cuál es la vía de infección más frecuente?", o:["Transmisión de gérmenes por las manos","Diseminación de gérmenes desde las mucosas respiratorias superiores","Parto vaginal","Contacto directo con secreciones respiratorias de familiares"], c:2, e:"La conjuntivitis neonatal (gonocócica o por clamidia) se adquiere clásicamente por contacto con secreciones del canal del parto durante el parto vaginal."},
{ex:"2025-A", n:62, area:"PED", tema:"Atresia duodenal", q:"RN masculino de 12 horas, vómitos biliosos sin distensión abdominal. Antecedente de polihidramnios. Rx abdominal: 'doble burbuja' sin aire distal. ¿Cuál es el diagnóstico?", o:["Mal rotación intestinal","Íleo meconial","Vólvulo intestinal","Atresia duodenal"], c:3, e:"El signo radiológico de 'doble burbuja' (estómago + duodeno proximal dilatados) sin aire distal es patognomónico de atresia duodenal."},
{ex:"2025-A", n:63, area:"GIN", tema:"Vacunación en el embarazo", q:"Primigesta de 28 semanas asintomática, acude a control prenatal. Ecografía morfológica sin alteraciones. La paciente pregunta por su esquema de inmunización. ¿Qué vacuna le corresponde?", o:["VPH","Rubéola","Tdap","Varicela"], c:2, e:"La vacuna dTpa (Tdap) se administra entre las 27-36 semanas de gestación para proteger al recién nacido de tos ferina en sus primeros meses de vida. VPH, rubéola y varicela son vacunas de virus vivo/no indicadas en el embarazo."},
{ex:"2025-A", n:64, area:"PED", tema:"Displasia broncopulmonar", q:"Lactante de 40 días, dificultad respiratoria. Antecedente: EG 32 semanas, cesárea, oxigenoterapia durante 32 días. FR 65X', FC 110X'. Sibilantes en ambos hemitórax y tirajes. ¿Cuál es el diagnóstico?", o:["Displasia broncopulmonar","Neumonía intrahospitalaria","Síndrome obstructivo bronquial","Bronquiolitis obliterante"], c:0, e:"Prematuro con oxigenoterapia prolongada (>28 días) que persiste con dificultad respiratoria crónica es el cuadro clásico de displasia broncopulmonar (enfermedad pulmonar crónica del prematuro)."},
{ex:"2025-A", n:65, area:"MED", tema:"Trastorno bipolar", q:"Mujer de 23 años, desde hace 2 años conducta extrovertida excesiva, impulsividad y estado de ánimo expansivo e irritable que alterna con episodios de apatía, indiferencia y anhedonia. ¿Cuál es el medicamento básico para el tratamiento?", o:["Paroxetina","Litio","Lorazepam","Mirtazapina"], c:1, e:"La alternancia de episodios de manía/hipomanía con depresión define el trastorno bipolar; el litio es el estabilizador del ánimo clásico de primera línea."},
{ex:"2025-A", n:66, area:"SP", tema:"Determinantes sociales de la salud", q:"El equipo de gestión del centro de salud elabora el ASIS y requiere incorporar un indicador de los determinantes sociales ambientales. ¿Cuál deberá elegir?", o:["Porcentaje de hogares con agua potable","Personal médico por cien mil habitantes","Tasa de reingresos hospitalarios","Cobertura de vacunación infantil"], c:0, e:"El acceso a agua potable es un determinante social ambiental clásico; los otros indicadores corresponden a oferta/desempeño de servicios de salud, no al entorno."},
{ex:"2025-A", n:67, area:"MED", tema:"Diabetes mellitus tipo 2 - inicio de insulina", q:"Mujer de 56 años con DM tipo 2, polidipsia y poliuria. IMC 32. HbA1c 10.8%. Glucosa basal 280 mg/dL. ¿Cuál es la conducta a seguir?", o:["Cambio de estilo de vida y control HbA1C","Iniciar insulinoterapia","Iniciar sulfonilureas","Solicitar prueba de tolerancia a la glucosa oral"], c:1, e:"Con HbA1c muy elevada (>10%) y síntomas cardinales de hiperglicemia marcada, se recomienda iniciar insulinoterapia de entrada, independientemente del tiempo de diagnóstico."},
{ex:"2025-A", n:68, area:"MED", tema:"Hipertensión en la postmenopausia", q:"¿Cuál es el mecanismo fisiológico por el cual se puede presentar hipertensión arterial en la postmenopausia?", o:["Cambios en la sensibilidad barorreceptora","Reducción de la actividad del sistema renina-angiotensina","Aumento en la resistencia vascular periférica","Pérdida del efecto protector del estrógeno"], c:3, e:"El estrógeno tiene un efecto vasodilatador/protector cardiovascular; su caída en la menopausia contribuye al aumento de la presión arterial en mujeres postmenopáusicas."},
{ex:"2025-A", n:69, area:"CIR", tema:"Infección necrotizante de tejidos blandos", q:"Varón de 20 años, hace 6 días sufre atropello con herida en el muslo derecho. Bordes negruzcos, ampollas con contenido rojo vinoso y secreción fétida. Hb 7.5 g/dL. ¿Cuál es el tratamiento prioritario?", o:["Antibióticos de amplio espectro","Transfusión sanguínea","Vacuna antitetánica","Desbridamiento y drenaje"], c:3, e:"Ante una infección necrotizante de tejidos blandos (bordes necróticos, ampollas hemorrágicas, secreción fétida), el desbridamiento quirúrgico urgente es la medida prioritaria que salva la vida, más que los antibióticos solos."},
{ex:"2025-A", n:70, area:"PED", tema:"Fiebre tifoidea", q:"Escolar de 8 años, desde hace cinco días fiebre, hiporexia, náusea, malestar general y dolor abdominal. Vivienda sin servicios básicos. Hepatoesplenomegalia. Leucopenia. ¿Cuál es el diagnóstico más probable?", o:["Dengue","Paludismo","Brucelosis","Fiebre tifoidea"], c:3, e:"Fiebre prolongada, dolor abdominal, hepatoesplenomegalia y leucopenia en contexto de saneamiento deficiente son característicos de fiebre tifoidea (Salmonella typhi)."},
{ex:"2025-A", n:71, area:"PED", tema:"Anemia de Fanconi", q:"Niño de 7 años, anemia refractaria al tratamiento con hierro. Manchas café con leche e hiperpigmentación cutánea; talla corta, pulgares y radios anormales, hipogonadismo, dismorfias en cabeza. ¿Cuál es el diagnóstico más probable?", o:["Anemia megaloblástica","Anemia de Fanconi","Síndrome de Shawchman-Diamond","Anemia regenerativa"], c:1, e:"Las anomalías del pulgar/radio junto con manchas café con leche, talla baja y falla medular progresiva son el fenotipo clásico de la anemia de Fanconi."},
{ex:"2025-A", n:72, area:"MED", tema:"Tuberculosis pleural", q:"Varón de 30 años, dolor torácico, fiebre, diaforesis nocturna y baja de peso. Antecedentes de inmunodeficiencia y consumo de sustancias ilícitas. Rx: derrame pleural derecho. ¿Cuál de las siguientes pruebas en el líquido pleural es útil para el diagnóstico de tuberculosis pleural?", o:["Proteínas bajas","Glucosa alta","DHL elevado","Test de ADA positivo"], c:3, e:"La adenosina deaminasa (ADA) elevada en líquido pleural es un marcador de alto rendimiento diagnóstico para tuberculosis pleural."},
{ex:"2025-A", n:73, area:"CB", tema:"Fisiopatología del daño celular isquémico", q:"Varón de 68 años con cardiopatía isquémica, sufre un IAM y desarrolla daño estructural celular extenso. ¿Cuál es el mecanismo predominante de daño celular irreversible en este contexto?", o:["Entrada masiva de calcio intracelular","Disminución del Na intracelular","Disminución del K extracelular","Detención de H+ intracelular"], c:0, e:"La entrada masiva y sostenida de calcio intracelular, con activación de proteasas y fosfolipasas, es el mecanismo final común del daño celular irreversible en la isquemia."},
{ex:"2025-A", n:74, area:"MED", tema:"Neumonía del adulto - alcoholismo", q:"Varón de 64 años, fiebre, escalofríos, cefalea, tos improductiva y dolor torácico. Antecedente de alcoholismo. T° 39.2°C; crepitantes y frote pleural. ¿Cuál es el examen de elección para confirmar su diagnóstico?", o:["RX tórax","Cultivo de esputo","Procalcitonina sérica","TC tórax con contraste"], c:0, e:"La radiografía de tórax es el estudio estándar inicial para confirmar el diagnóstico de neumonía adquirida en la comunidad."},
{ex:"2025-A", n:75, area:"GIN", tema:"Terapia hormonal en la menopausia tardía", q:"Mujer de 57 años, solicita terapia de reemplazo hormonal, bochornos dos veces al día. FUR hace 10 años. ¿Cuál es la conducta a seguir?", o:["Estrógenos parenterales","Medidas higiénico dietéticas","Estrógenos vía oral","Estrógeno más progesterona"], c:1, e:"Al haber transcurrido más de 10 años desde la menopausia, se está fuera de la 'ventana de oportunidad' para iniciar THR sistémica (mayor riesgo cardiovascular/trombótico); se prefieren medidas no hormonales."},
{ex:"2025-A", n:76, area:"PED", tema:"Pie plano flexible", q:"Escolar de 7 años, aplanamiento plantar bilateral asintomático. Disminución del arco plantar y valgo de retropié; en bipedestación el arco desaparece (pero reaparece al no cargar peso). ¿Cuál es el diagnóstico del pie plano?", o:["Neurológico","Con contractura","Flexible","Rígido congénito"], c:2, e:"El pie plano que desaparece en descarga y es asintomático corresponde al pie plano flexible, la variante benigna más frecuente y fisiológica en la infancia."},
{ex:"2025-A", n:77, area:"MED", tema:"Taquicardia por reentrada nodal", q:"Varón de 25 años, palpitaciones y dolor precordial. FC 155X'. EKG compatible con taquicardia de reentrada nodal auriculoventricular. ¿Cuál es el tratamiento de elección?", o:["Labetalol","Cardioversión eléctrica","Amiodarona","Adenosina"], c:3, e:"La adenosina endovenosa en bolo rápido es el fármaco de elección para revertir la TRNAV (TPSV) en el paciente estable."},
{ex:"2025-A", n:78, area:"PED", tema:"Atresia esofágica con fístula", q:"RN a término con dificultad respiratoria, sialorrea y asfixia con la primera alimentación oral. La sonda nasogástrica no progresa más allá de 10 cm. Rx: sonda enrollada en esófago superior, presencia de aire en estómago e intestinos. ¿Cuál es el diagnóstico?", o:["Fístula traqueoesofágica aislada","Atresia esofágica con fístula traqueoesofágica","Estenosis pilórica","Anillo vascular"], c:1, e:"La sonda enrollada en el esófago superior confirma atresia esofágica; la presencia de aire distal en el tracto digestivo indica que existe una fístula traqueoesofágica distal asociada (tipo C, la más frecuente)."},
{ex:"2025-A", n:79, area:"MED", tema:"Delirium tremens", q:"Varón de 52 años, alcohólico crónico, cefalea y temblor; se agrega desorientación, agitación y alucinaciones visuales tras convulsiones tónico clónicas. Último episodio de ingesta de alcohol hace 2 días. ¿Cuál es el tratamiento de elección?", o:["Tiamina","Diazepam","Dextrosa 33%","Fenitoina"], c:1, e:"El delirium tremens (síndrome de abstinencia alcohólica grave) se trata con benzodiacepinas, siendo el diazepam el fármaco de elección para controlar la agitación y prevenir convulsiones."},
{ex:"2025-A", n:80, area:"CIR", tema:"Ayuno preanestésico", q:"Mujer de 25 años programada para colecistectomía por colecistitis aguda, refiere haber ingerido un vaso de limonada azucarada una hora antes de la intervención. ¿Cuál es la conducta adecuada?", o:["Se administra un antiemético y se procede","Postergar la cirugía por 2 horas","Postergar la cirugía por 24 horas","Se monitoriza de cerca durante la inducción anestésica"], c:1, e:"Las guías de ayuno preanestésico permiten líquidos claros hasta 2 horas antes de la cirugía; al haber ingerido hace solo 1 hora, se debe postergar hasta completar ese margen de seguridad."},
{ex:"2025-A", n:81, area:"MED", tema:"Marcadores pronósticos en sepsis", q:"¿Cuál es el marcador pronóstico cuyo valor en sangre permite monitorizar la evolución, y está asociado a mayor mortalidad y progresión a disfunción orgánica en sepsis?", o:["Procalcitonina","Lactato","PCR","Glucemia"], c:1, e:"El lactato sérico refleja hipoperfusión tisular y es el marcador pronóstico y de monitorización de respuesta al tratamiento más usado en sepsis/shock séptico."},
{ex:"2025-A", n:82, area:"PED", tema:"Atresia esofágica sin fístula distal", q:"Neonato de 2 horas, sialorrea súbita, tos y cianosis durante la alimentación. Antecedente: cesárea, líquido amniótico aumentado (polihidramnios). Abdomen escafoideo, RHA ausentes. ¿Cuál es el diagnóstico más probable?", o:["Neumonía por aspiración meconial","Fístula traqueoesofágica tipo H","Atresia esofágica","Hernia diafragmática"], c:2, e:"Polihidramnios + abdomen escafoideo (sin aire) + intolerancia a la primera toma sugiere atresia esofágica pura, sin fístula distal (el aire no llega al abdomen)."},
{ex:"2025-A", n:83, area:"MED", tema:"Diagnóstico de tuberculosis con baciloscopia negativa", q:"Adulto de 28 años con dos baciloscopias negativas, con alta probabilidad de TB clínica activa según criterio médico. ¿Cuál es la conducta a seguir según marco normativo nacional?", o:["PPD y cultivo","Iniciar tratamiento","Alta y control anual","PDR m y cultivo"], c:3, e:"Ante baciloscopia negativa pero alta sospecha clínica de TB, la norma nacional indica proseguir con prueba molecular rápida (PDRm) y cultivo, que tienen mayor sensibilidad."},
{ex:"2025-A", n:84, area:"PED", tema:"Onfalitis localizada", q:"Recién nacido de 10 días. FC 100X', FR 50X', T° 37.2°C. Cordón umbilical presente, húmedo, con secreción amarillenta mal oliente y eritema periumbilical. Hemograma: leucocitos 10,000/uL, abastonados 0. ¿Cuál es el diagnóstico más probable?", o:["Onfalocele","Onfalitis","Peritonitis","Celulitis"], c:1, e:"Secreción purulenta y eritema periumbilical localizado, sin signos sistémicos ni laboratorio alterado, corresponde a onfalitis localizada (leve)."},
{ex:"2025-A", n:85, area:"PED", tema:"Torsión testicular", q:"Niño de 10 años, dolor testicular derecho súbito desde hace 3 horas, náusea. Testículo en posición alta, edematoso, muy doloroso. Doppler: disminución del flujo arterial en el testículo comprometido. ¿Cuál es el diagnóstico?", o:["Torsión testicular","Orquitis","Epididimitis","Varicocele"], c:0, e:"Dolor testicular súbito, testículo elevado y doloroso con flujo doppler disminuido es torsión testicular, urgencia quirúrgica con ventana de rescate menor a 6 horas."},
{ex:"2025-A", n:86, area:"MED", tema:"Malaria", q:"Varón de 35 años, residente de Quillabamba (valle tropical), fiebre alta intermitente, esplenomegalia y anemia severa de progresión rápida; picaduras de insectos al amanecer y anochecer. Frotis: parásito en eritrocitos. ¿Cuál es la característica inmunológica del huésped crucial para los paroxismos febriles?", o:["Inducción de autoanticuerpos contra eritrocitos","Liberación de citoquinas proinflamatorias","Formación de hipnozoitos hepáticos","Liberación de T killer contra eritrocitos parasitados"], c:1, e:"Los paroxismos febriles de la malaria coinciden con la ruptura sincrónica de eritrocitos infectados, que libera antígenos parasitarios y desencadena una intensa respuesta de citoquinas proinflamatorias (TNF, IL-1, IL-6)."},
{ex:"2025-A", n:87, area:"MED", tema:"Anemia megaloblástica por déficit de B12", q:"Mujer de 64 años, gastrectomía parcial hace 2 años. Anorexia, diarrea, pérdida de peso, parestesia en MMII y marcha atáxica. Palidez, glositis, lengua depapilada. Hb 7.5 g/dL, VCM 110 fL, polisegmentación de neutrófilos. ¿Cuál es el tratamiento de elección?", o:["Riboflavina","Tiamina","Niacina","Cobalamina"], c:3, e:"La gastrectomía elimina la producción de factor intrínseco, causando déficit de vitamina B12 (macrocitosis, neutrófilos hipersegmentados, compromiso neurológico); el tratamiento es cobalamina."},
{ex:"2025-A", n:88, area:"PED", tema:"Ictericia por lactancia materna", q:"Neonato de 12 días, recibe lactancia materna exclusiva, ictericia hasta raíz de muslos, activo y reactivo, succión vigorosa. Bilirrubina total 18 mg/dL a predominio indirecta; madre A+ y neonato O+. ¿Cuál es el diagnóstico más probable?", o:["Ictericia por lactancia materna","Deficiencia de G6PD","Incompatibilidad ABO","Sepsis neonatal"], c:0, e:"Al no existir incompatibilidad ABO real (la madre no es del grupo O), y con un bebé sano y bien alimentado con hiperbilirrubinemia indirecta persistente después de la primera semana, el diagnóstico más probable es ictericia por leche materna."},
{ex:"2025-A", n:89, area:"SP", tema:"Error estadístico tipo I", q:"Un estudio sobre incidencia de anemia entre gestantes expuestas y no expuestas a la dieta 'A' demostró una diferencia con p<0.05. Si los niveles de hemoglobina en ambos grupos NO presentan diferencia real, ¿cuál es el tipo de error?", o:["II","1-a","1-p","I"], c:3, e:"Concluir que existe una diferencia estadísticamente significativa cuando en realidad no la hay (falso positivo) es el error tipo I (alfa)."},
{ex:"2025-A", n:90, area:"PED", tema:"Hipoglicemia neonatal", q:"Recién nacido de 37 semanas, peso 2000 g (bajo peso), letárgico, náuseas, succión débil y temblores finos en las primeras horas de vida. Glicemia capilar 39 mg/dL. ¿Cuál es la causa más probable?", o:["Disminución de reservas energéticas","Adaptación metabólica transitoria","Hiperinsulinismo congénito","Asfixia perinatal"], c:0, e:"El bajo peso para la edad gestacional se asocia a reservas de glucógeno hepático disminuidas, lo que predispone a hipoglicemia neonatal precoz por depleción de reservas."},
{ex:"2025-A", n:91, area:"PED", tema:"Parasitosis - Balantidium coli", q:"Niño de 6 años, procedente de la sierra, dolor abdominal, náusea y deposiciones sanguinolentas desde hace un mes. Antecedente de vivienda rústica con crianza de cerdos. ¿Cuál es el agente etiológico más probable?", o:["Cryptosporidium","Balantidium coli","Giardia lamblia","Cyclospora"], c:1, e:"Balantidium coli es un protozoario ciliado transmitido por contacto con heces de cerdos, causante de colitis con deposiciones sanguinolentas (disentería balantidiana)."},
{ex:"2025-A", n:92, area:"PED", tema:"Estreñimiento funcional", q:"Niño de 16 meses, dificultad para evacuar desde hace tres semanas; vómitos y alza térmica no cuantificada. Antecedente de estreñimiento intermitente. Abdomen moderadamente distendido, depresible y doloroso. ¿Cuál es la conducta inicial a seguir?", o:["Rx abdomen de pie","Resonancia abdominal","Enemas evacuantes","Polietilenglicol en gastroclisis"], c:0, e:"Ante estreñimiento prolongado con distensión y sospecha de fecaloma/suboclusión, la radiografía simple de abdomen de pie es el primer estudio para evaluar la carga fecal y descartar obstrucción antes de tratar."},
{ex:"2025-A", n:93, area:"CB", tema:"Fisiología - hipokalemia", q:"Mujer de 18 años, debilidad muscular progresiva y constipación. Usa diuréticos para bajar de peso. EKG: aplanamiento de onda T y aparición de onda U. ¿Cuál es el efecto esperado en el potencial de acción de las neuronas motoras?", o:["Aumenta el umbral necesario para la generación del potencial de acción","Genera una repolarización más lenta por disminución de la conductancia de K⁺","Disminuye la excitabilidad neuronal por hiperpolarización","Prolonga la duración del potencial de acción dificultando la despolarización"], c:1, e:"La hipokalemia reduce la conductancia de potasio de la membrana, enlenteciendo la fase de repolarización (explica el aplanamiento de la onda T y la aparición de onda U en el EKG)."},
{ex:"2025-A", n:94, area:"MED", tema:"Neuralgia del trigémino", q:"Mujer de 64 años, episodios intermitentes de dolor intenso en labios, encías y pómulos que se intensifican al contacto. Examen y RM normales. ¿Cuál es el diagnóstico más probable?", o:["Neurinoma acústico","Meningioma","Parálisis del nervio facial","Neuralgia del trigémino"], c:3, e:"Dolor paroxístico intenso, tipo descarga eléctrica, en el territorio del trigémino, gatillado por contacto (zonas gatillo), con RM normal, es característico de neuralgia del trigémino idiopática."},
{ex:"2025-A", n:95, area:"PED", tema:"Deshidratación hipernatrémica del neonato", q:"RN de 8 días, pobre ganancia ponderal, irritabilidad, orina escasa y pobre succión. Nacido por cesárea, alta conjunta, madre adolescente con embarazo controlado. Ictericia hasta raíz de muslos, adelgazado y llanto enérgico. ¿Cuál es el diagnóstico más probable?", o:["Ictericia neonatal","Deshidratación hipernatrémica","Hipoglicemia","Sepsis neonatal"], c:1, e:"Pobre ganancia ponderal, orina escasa y adelgazamiento en un neonato con lactancia materna insuficiente (madre primeriza inexperta) es el cuadro clásico de deshidratación hipernatrémica por lactancia materna deficiente."},
{ex:"2025-A", n:96, area:"PED", tema:"Sífilis congénita", q:"Lactante de 40 días, referido por presentar desde el nacimiento coriza y hace 3 días lactancia entrecortada. Recibe corticoides nasales y clorfeniramina sin mejoría. Ictericia hasta abdomen, hepatomegalia. ¿Cuál es el diagnóstico más probable?", o:["Sífilis congénita","Atresia biliar","Toxoplasmosis congénita","Atresia de coanas"], c:0, e:"La rinitis persistente desde el nacimiento ('coriza sifilítica') que no responde a tratamiento habitual, asociada a hepatomegalia e ictericia, es característica de sífilis congénita."},
{ex:"2025-A", n:97, area:"PED", tema:"Pitiriasis alba", q:"Adolescente de 12 años, hace 2 meses manchas blancas en cara. Máculas hipocrómicas redondeadas, algunas eritematosas, bordes no definidos, descamación escasa en cara y tórax. ¿Cuál es el diagnóstico?", o:["Pitiriasis alba","Tiña versicolor","Dermatitis seborreica","Vitíligo"], c:0, e:"Máculas hipocrómicas de bordes mal definidos con descamación fina en cara de niños/adolescentes (frecuentemente atópicos) es pitiriasis alba, entidad benigna y autolimitada."},
{ex:"2025-A", n:98, area:"MED", tema:"Leishmaniasis cutánea", q:"Joven procedente de área rural andina presenta úlcera cutánea grande e indolora con bordes elevados e indurados. Biopsia: amastigotes dentro de macrófagos. ¿Cuál es el agente causal más probable?", o:["Trypanosoma cruzi","Leishmania braziliensis","Leishmania donovani","Mycobacterium leprae"], c:1, e:"La úlcera cutánea indolora de bordes elevados con amastigotes en macrófagos es leishmaniasis cutánea; en el Perú la especie prevalente en la vertiente andina es Leishmania (Viannia) braziliensis (uta)."},
{ex:"2025-A", n:99, area:"GIN", tema:"Absceso mamario", q:"Puérpera de 33 años, fiebre y congestión mamaria desde hace 3 días. Se inicia dicloxacilina y compresas; luego de 72 horas continúa febril. Ecografía mamaria: colección de 45 mm. ¿Cuál es la conducta más adecuada?", o:["Rotación de antibiótico","Extracción vigorosa de leche","Drenaje quirúrgico","Compresas tibias"], c:2, e:"Una mastitis que evoluciona a absceso confirmado por ecografía (colección) requiere drenaje (quirúrgico o percutáneo), ya que los antibióticos solos no resuelven una colección purulenta organizada."},
{ex:"2025-A", n:100, area:"GIN", tema:"Síndrome de ovario poliquístico", q:"Mujer de 24 años con irregularidades menstruales desde hace dos años, hirsutismo leve, IMC 20. Glucosa en ayunas 80 mg/dL. ¿Cuál es el tratamiento más adecuado?", o:["Metformina","Anticonceptivos orales combinados","Espironolactona","Finasteride"], c:1, e:"En SOP con fenotipo no obeso y sin deseo inmediato de gestación, los anticonceptivos orales combinados son primera línea para regularizar ciclos y mejorar el hirsutismo."},
{ex:"2025-B", n:1, area:"CIR", tema:"Trauma torácico penetrante", q:"Varón de 21 años, sufrió asalto con arma de fuego, ingresa con disnea y hemoptisis. PA 90/50 mmHg, FR 30X', SatO2 90%; orificio de entrada a nivel de HTD tercio medio, enfisema subcutáneo, MV abolido en HTD. ¿Cuál es la estructura anatómica afectada?", o:["Vena cava superior","Diafragma","Árbol traqueobronquial","Arteria torácica interna"], c:2, e:"Hemoptisis + enfisema subcutáneo masivo + MV abolido tras trauma penetrante de tórax sugiere lesión del árbol traqueobronquial."},
{ex:"2025-B", n:2, area:"PED", tema:"Síndrome de Down", q:"RN de parto eutócico, EG 38 semanas, APGAR 8-9. Cara: puente nasal aplanado, ojos almendrados con pliegue epicántico, orejas pequeñas. Línea única en la palma, flacidez y reflejo de succión alterado. ¿Cuál es el síndrome?", o:["Crouzon","Apert","Treacher Collins","Down"], c:3, e:"Puente nasal plano, pliegue epicántico, línea palmar única (pliegue simiesco) e hipotonía son rasgos característicos del síndrome de Down (trisomía 21)."},
{ex:"2025-B", n:3, area:"MED", tema:"Peritonitis asociada a diálisis peritoneal", q:"Mujer de 48 años en diálisis peritoneal, fiebre, náusea, dolor y distensión abdominal. T° 38.6°C; líquido de diálisis turbio. Recuento celular en líquido peritoneal 520/µL; PMN 90%. ¿Cuál es el tratamiento de elección?", o:["Gentamicina + vancomicina","Vancomicina","Ceftriaxona","Ceftriaxona + gentamicina"], c:0, e:"La peritonitis asociada a diálisis peritoneal se cubre empíricamente con un esquema que cubra gram positivos (vancomicina) y gram negativos (aminoglucósido), vía intraperitoneal."},
{ex:"2025-B", n:4, area:"MED", tema:"Tromboangeítis obliterante (Buerger)", q:"Varón de 35 años, fumador desde los 14 años, frialdad distal asimétrica de extremidades. Pulsos disminuidos en mano derecha; prueba de Allen (+), úlcera isquémica en 2° dedo de pie izquierdo. ¿Cuál es la morfología en la anatomía patológica?", o:["Engrosamiento de la íntima con placas ateromatosas y trombos superpuestos","Vasos con inflamación, obstruidos por trombos con microabscesos de neutrófilos","Células inflamatorias dispersas con calcificación y neovascularización","Vasos con densos cúmulos de células atípicas ocluyendo la luz"], c:1, e:"La tromboangeítis obliterante (enfermedad de Buerger), típica de fumadores jóvenes con isquemia distal de varias extremidades, se caracteriza histológicamente por trombos inflamatorios con microabscesos de neutrófilos, respetando la pared vascular."},
{ex:"2025-B", n:5, area:"GIN", tema:"Prolapso genital - POP-Q", q:"Mujer de 75 años, sensación de bulto vaginal, sin escape de orina. POPQ: Aa 0, Ba +1; longitud total de la vagina 7 cm. ¿Cuál es el grado del prolapso?", o:["IV","I","II","III"], c:2, e:"Un punto Ba en +1 (dentro del rango entre -1 y +1 respecto al himen) corresponde a un prolapso estadio II según la clasificación POP-Q."},
{ex:"2025-B", n:6, area:"PED", tema:"Fractura en rodete (torus)", q:"¿Cuál es la indicación terapéutica de la fractura en rodete del radio a nivel de la metáfisis sin desplazamiento en el niño?", o:["Fijación externa","Reducción incruenta","Inmovilización antiálgica","Completar la fractura"], c:2, e:"La fractura en rodete (torus) es una fractura estable e incompleta típica del hueso infantil; se trata solo con inmovilización antiálgica (férula/yeso), sin necesidad de reducción."},
{ex:"2025-B", n:7, area:"PED", tema:"Varicela diseminada en inmunocomprometido", q:"Niña de 14 años con leucemia en tratamiento, dolor urente en pierna derecha y dificultad respiratoria desde hace 7 días. Contacto con abuela hace 15 días. Numerosas pápulas con costra y escara central en pierna, cuello y cuero cabelludo. ¿Cuál es el diagnóstico más probable?", o:["Infección micótica diseminada","Osteomielitis","Infección por herpes simple","Infección por VVZ"], c:3, e:"En un paciente inmunocomprometido con exposición reciente a varicela y lesiones vesiculares diseminadas con compromiso pulmonar, se trata de varicela diseminada grave (virus varicela-zóster)."},
{ex:"2025-B", n:8, area:"PED", tema:"Rinosinusitis bacteriana", q:"Niño de 13 años, hace 10 días rinorrea y tos con flema que no cede con antihistamínicos; hace 2 días malestar general, fiebre, cefalea, hiposmia e hiporexia. Antecedente de rinitis alérgica y asma. Secreción purulenta descendente, dolor a la presión frontal. ¿Cuál es el tratamiento inicial?", o:["Amoxicilina más ácido clavulánico","Ceftriaxona","Amoxicilina","Azitromicina"], c:0, e:"El patrón de 'doble empeoramiento' (mejoría inicial y luego reagravamiento tras 10 días) sugiere sinusitis bacteriana; en un paciente con factores de riesgo se prefiere amoxicilina/clavulánico sobre amoxicilina sola."},
{ex:"2025-B", n:9, area:"GIN", tema:"Adenomiosis", q:"Mujer de 44 años, hipermenorrea y dismenorrea desde hace 2 años. Antecedente de 4 cesáreas y ligadura tubárica. TV: útero 10 cm globuloso. Ecografía: pared miometrial anterior más gruesa que la posterior, miometrio heterogéneo; endometrio 8 mm homogéneo. Hb 9 g/dL. ¿Cuál es el diagnóstico más probable?", o:["Pólipo endometrial","Endometriosis","Adenomiosis","Miomatosis uterina"], c:2, e:"El engrosamiento miometrial asimétrico con textura heterogénea (sin masas focales definidas como en miomatosis) en una mujer multípara con cesáreas previas es característico de adenomiosis."},
{ex:"2025-B", n:10, area:"CIR", tema:"Luxación de cadera", q:"¿Cuál de las luxaciones de la cadera del adulto se caracteriza solo por un ligero acortamiento del miembro inferior?", o:["Posterior","Central","Externa","Anterior"], c:1, e:"La luxación central (fractura-luxación hacia la pelvis) produce solo un ligero acortamiento, a diferencia de la posterior (acortamiento marcado, aducción y rotación interna) o la anterior (abducción y rotación externa)."},
{ex:"2025-B", n:11, area:"MED", tema:"Asma potencialmente mortal", q:"Mujer de 45 años, asma bronquial, dificultad respiratoria, cianosis. PA 90/60 mmHg, FC 125X', SatO2 88%; habla con palabras entrecortadas, cianosis distal; tórax silente; despierta. ¿Cuál es la manifestación de asma potencialmente mortal?", o:["Taquicardia","Tórax silente","Desaturación","Cianosis"], c:1, e:"El 'tórax silente' (ausencia de sibilancias por flujo aéreo mínimo) es el signo más ominoso de crisis asmática potencialmente mortal, indicando obstrucción casi total."},
{ex:"2025-B", n:12, area:"GIN", tema:"Sífilis primaria", q:"Mujer de 28 años, lesiones en zona vulvar. Antecedente de inicio de relaciones sexuales a los 17 años y múltiples parejas. Vulva: tres lesiones tipo úlcera de base limpia y bordes redondeados elevados, no dolorosas; sin linfadenopatía inguinal. ¿Cuál es el agente etiológico más probable?", o:["Virus herpes simple","Treponema pallidum","Haemophilus ducrey","Virus del papiloma humano"], c:1, e:"Úlceras genitales indoloras, de base limpia y bordes indurados (chancro), son características de la sífilis primaria por Treponema pallidum."},
{ex:"2025-B", n:13, area:"PED", tema:"Faringoamigdalitis - alergia a betalactámicos", q:"Niño de 7 años, dolor de garganta y fiebre alta. Faringe con exudado; ganglios cervicales grandes y dolorosos. Se decide tratamiento antibiótico, pero es alérgico a betalactámicos. ¿Cuál es el antibiótico alternativo de elección?", o:["Tetraciclinas","Macrólidos","Quinolonas","Sulfonamidas"], c:1, e:"En faringoamigdalitis estreptocócica con alergia a penicilina, los macrólidos (eritromicina, azitromicina, claritromicina) son la alternativa estándar."},
{ex:"2025-B", n:14, area:"MED", tema:"Profilaxis post-exposición VIH", q:"Adolescente de 16 años, tuvo relación sexual no protegida hace 48 h con pareja de estado serológico desconocido. ¿Cuál es la intervención inicial?", o:["Solicitar pruebas serológicas para VIH y sífilis para iniciar profilaxis","Administrar tratamiento antibiótico profiláctico para ITS","Evaluación de riesgo y decidir profilaxis con resultados de la pareja","Iniciar profilaxis post exposición con tenofovir, lamivudina y dolutegravir por 28 días"], c:3, e:"La profilaxis post-exposición al VIH debe iniciarse lo antes posible (idealmente <72 horas) sin esperar resultados serológicos de la pareja, dado que cada hora de retraso reduce su eficacia."},
{ex:"2025-B", n:15, area:"GIN", tema:"Fisiología del parto - CRH placentaria", q:"¿Cuál es la hormona proteica producida por células del sincitiotrofoblasto y del trofoblasto placentario, cuya concentración aumenta a lo largo del embarazo, alcanza su máximo en el trabajo de parto y participa en su inicio?", o:["Estradiol","Cortisol","Liberadora de corticotropina","Tiroxina"], c:2, e:"La hormona liberadora de corticotropina (CRH) placentaria aumenta progresivamente durante la gestación y actúa como un 'reloj placentario' que participa en el desencadenamiento del trabajo de parto."},
{ex:"2025-B", n:16, area:"PED", tema:"Síndrome conjuntivitis-otitis", q:"La aparición simultánea de conjuntivitis purulenta y eritematosa con otitis media ipsilateral se debe a...", o:["Moraxella catarrhalis","Haemophilus influenzae","Virus sincitial respiratorio","Streptococcus pneumoniae"], c:1, e:"El 'síndrome conjuntivitis-otitis' (aparición simultánea de ambas infecciones) está clásicamente asociado a Haemophilus influenzae no tipificable."},
{ex:"2025-B", n:17, area:"MED", tema:"Leucemia mieloide aguda", q:"Varón de 45 años, fatiga, anorexia, pérdida de peso, dolor en extremidades, diaforesis y tos. Equimosis en extremidades, adenopatías cervicales no dolorosas, hepatoesplenomegalia. Hemograma: bastones de Auer. ¿Cuál es el diagnóstico más probable?", o:["Policitemia vera","Linfoma no Hodgkin","Leucemia mieloide aguda","Tuberculosis ganglionar"], c:2, e:"Los bastones de Auer (agregados de gránulos azurófilos) son patognomónicos de la leucemia mieloide aguda."},
{ex:"2025-B", n:18, area:"MED", tema:"Hipotiroidismo primario", q:"Mujer de 50 años, fatiga progresiva, ganancia de peso, intolerancia al frío y piel seca. Facies pálida y edema palpebral. TSH 15 mUI/L, T4 libre 0.6 ng/dL, anti-TPO positivos. ¿Cuál es el manejo inicial más apropiado?", o:["Solicitar ecografía tiroidea","Iniciar levotiroxina","Solicitar gammagrafía tiroidea","Repetir perfil tiroideo en 6 meses"], c:1, e:"TSH elevada con T4 libre baja y anticuerpos anti-TPO positivos confirman hipotiroidismo primario autoinmune (tiroiditis de Hashimoto); el manejo es iniciar levotiroxina."},
{ex:"2025-B", n:19, area:"CIR", tema:"Hemotórax masivo", q:"Mujer de 35 años, herida de bala en 4to espacio intercostal derecho sin orificio de salida. PA 90/60 mmHg, MV abolido en hemitórax derecho. Rx: hemoneumotórax y fractura de 5ta costilla. Al insertar tubo de tórax drena más de 1500 ml de sangre. ¿Cuál es la conducta a seguir?", o:["Toracotomía","Observación","Toracostomía","Tomografía"], c:0, e:"Un drenaje inicial mayor a 1500 ml (o >200 ml/h sostenido) por el tubo de tórax define hemotórax masivo y es indicación de toracotomía de urgencia."},
{ex:"2025-B", n:20, area:"PED", tema:"Osteogénesis imperfecta", q:"Madre trae a neonato de parto eutócico, sin control prenatal ni ecografías. Escleras azuladas, acortamiento y arqueamiento de extremidades. Rx: hipomineralización de huesos largos. ¿Cuál es la anomalía embriológica más probable?", o:["Síndrome de Marfan","Síndrome de Turner","Osteogénesis imperfecta","Artrogriposis"], c:2, e:"Escleras azules + fragilidad ósea con hipomineralización y deformidad de huesos largos son el cuadro clásico de osteogénesis imperfecta (defecto del colágeno tipo I)."},
{ex:"2025-B", n:21, area:"PED", tema:"Retinopatía del prematuro - seguimiento", q:"Recién nacido prematuro de 36 semanas, dado de alta de neonatología. A los 21 días, evaluación oftalmológica reporta retina inmadura. ¿Cuál es el intervalo en semanas recomendado para su control oftalmológico?", o:["3","4","6","2"], c:3, e:"Ante retina inmadura sin signos de retinopatía del prematuro establecida, el seguimiento oftalmológico estrecho recomendado es cada 2 semanas."},
{ex:"2025-B", n:22, area:"MED", tema:"Conjuntivitis tóxica por preservantes", q:"Mujer de 50 años, irritación, quemazón ocular y sensación de cuerpo extraño desde hace 2 días. Uso frecuente de colirios con cloruro de benzalconio. Hiperemia conjuntival, reacción papilar y queratitis punteada superficial. ¿Cuál es el diagnóstico?", o:["Conjuntivitis tóxica","Uveitis anterior aguda","Epiescleritis aguda","Glaucoma agudo"], c:0, e:"El uso crónico de colirios con conservantes (cloruro de benzalconio) puede causar toxicidad epitelial corneal y conjuntival: conjuntivitis tóxica medicamentosa."},
{ex:"2025-B", n:23, area:"GIN", tema:"Preeclampsia severa en trabajo de parto", q:"Multigesta de 39 semanas, dolor tipo contracción, cefalea y escotomas. PA 160/100 mmHg. Dilatación 9 cm, borramiento 80%. Patrón fetal categoría I. Se inicia sulfato de magnesio. ¿Cuál es la conducta a seguir?", o:["Uso de diuréticos","Acentuación con oxitocina","Manejo expectante","Cesárea de emergencia"], c:1, e:"Con preeclampsia severa pero trabajo de parto avanzado (9 cm) y feto con patrón tranquilizador (categoría I), se favorece completar el parto vaginal acentuando con oxitocina, bajo cobertura de sulfato de magnesio."},
{ex:"2025-B", n:24, area:"MED", tema:"Seguimiento de hipotiroidismo tratado", q:"Mujer de 48 años, hipotiroidismo con TSH elevada y T4 libre suprimida, inicia tratamiento con levotiroxina. ¿A los cuántos meses se valora la respuesta de la TSH?", o:["4","5","3","2"], c:3, e:"La respuesta de la TSH al ajuste de la dosis de levotiroxina se evalúa aproximadamente a las 6-8 semanas (alrededor de 2 meses), tiempo en que la TSH alcanza un nuevo estado estable."},
{ex:"2025-B", n:25, area:"CB", tema:"Farmacología de anestésicos locales", q:"Se requiere un mayor tiempo de acción anestésica local que lo habitual, para lo que se recomienda administrar un vasoconstrictor como la epinefrina. ¿Cuál es el anestésico local indicado?", o:["Lidocaína","Ropivacaína","Cocaína","Bupivacaína"], c:0, e:"La lidocaína, de duración intermedia-corta, se beneficia clásicamente de la adición de epinefrina para prolongar su efecto; los anestésicos de larga duración (bupivacaína, ropivacaína) la requieren menos."},
{ex:"2025-B", n:26, area:"MED", tema:"Meningitis bacteriana - manejo inicial", q:"Varón de 40 años, desde hace 36 horas cefalea intensa y fiebre de 39°C. Somnolencia y rigidez de nuca. ¿Cuál es la conducta inicial a seguir?", o:["Hemocultivos, antibioticoterapia empírica y dexametasona","RMN con contraste","TC cerebral sin contraste","Tratamiento antibiótico empírico con dexametasona"], c:0, e:"Ante sospecha de meningitis bacteriana no se debe retrasar el tratamiento: se toman hemocultivos e inicia antibioticoterapia empírica junto con dexametasona de inmediato."},
{ex:"2025-B", n:27, area:"MED", tema:"Cirrosis hepática - espironolactona", q:"En pacientes con cirrosis hepática alcohólica con ascitis grado 3, ¿cuál es la dosis máxima de espironolactona en mg/día?", o:["160","400","80","200"], c:1, e:"La dosis máxima recomendada de espironolactona en el manejo de la ascitis cirrótica es de 400 mg/día."},
{ex:"2025-B", n:28, area:"CIR", tema:"Dedo en martillo", q:"Adolescente escolar, tras jugar béisbol, la parte proximal del segundo dedo choca con una base, originando dedo en martillo. ¿Cuál es la estructura anatómica afectada?", o:["Tendón extensor radial del carpo","Tendón extensor ulnar del carpo","Tendón extensor de la falange distal","Fascia profunda del antebrazo"], c:2, e:"El 'dedo en martillo' (mallet finger) es la lesión/avulsión del tendón extensor en su inserción en la falange distal, que impide la extensión activa de esa articulación."},
{ex:"2025-B", n:29, area:"CIR", tema:"Anestesia local - infiltración", q:"Niño de 5 años, herida en mano derecha de 3 cm de largo y profundidad menor a 5 mm. ¿Cuál es el tipo de anestesia indicada?", o:["Inhalatoria","Infiltración","Trócular","Tópica"], c:1, e:"Para la sutura de una herida superficial simple, la anestesia local por infiltración es el método estándar."},
{ex:"2025-B", n:30, area:"GIN", tema:"Bacteriuria asintomática en el embarazo", q:"Gestante de 12 semanas asintomática, segundo control prenatal, urocultivo positivo a E. coli sensible a nitrofurantoina. ¿Cuál es la dosis recomendada?", o:["100 mg cada 6 h por 3 días","100 mg al acostarse por 3 días","100 mg cada 6 h por 21 días","100 mg dosis única"], c:0, e:"La bacteriuria asintomática en la gestante siempre se trata; un esquema corto habitual con nitrofurantoína es 100 mg cada 6 horas por 3 días."},
{ex:"2025-B", n:31, area:"SP", tema:"Brote de intoxicación alimentaria", q:"En el comedor de un centro educativo, 30 escolares almuerzan arroz recalentado con lenteja y son llevados a urgencia por náusea y vómitos; todos los que consumieron el almuerzo presentaron síntomas. ¿Cuál es el agente etiológico más probable de este brote?", o:["Bacillus cereus","Campylobacter","Clostridium perfringens","Salmonella no typhi"], c:0, e:"El arroz recalentado es el vehículo clásico de la toxina emética de Bacillus cereus, causando síntomas de inicio rápido (náusea/vómitos) en todos los comensales."},
{ex:"2025-B", n:32, area:"GIN", tema:"Tamizaje de diabetes gestacional", q:"Primigesta de 8 semanas, antecedente de macrosomía al nacimiento (ella). IMC 24. ¿Cuál es su recomendación más importante con respecto a su control prenatal?", o:["Continuar su control prenatal habitual","Uso de metformina profiláctica","Mantener dieta hipoglúcida","Test de tolerancia oral a la glucosa a las 26 semanas"], c:3, e:"El antecedente personal de macrosomía al nacer es un factor de riesgo para diabetes gestacional; se mantiene el tamizaje estándar con PTOG entre las 24-28 semanas."},
{ex:"2025-B", n:33, area:"GIN", tema:"Vaginosis bacteriana", q:"Mujer de 32 años, dolor pélvico, malestar general y flujo vaginal. Especuloscopía: flujo gris con mal olor; se aisla Gardnerella vaginalis. ¿Cuál es el tratamiento de elección?", o:["Metronidazol","Ciprofloxacino","Doxiciclina","Azitromicina"], c:0, e:"El metronidazol (oral o vaginal) es el tratamiento de elección para la vaginosis bacteriana por Gardnerella vaginalis."},
{ex:"2025-B", n:34, area:"PED", tema:"Parálisis facial por otitis crónica", q:"Niño de 11 años con otitis media crónica supurada derecha, presenta parálisis en hemicara del mismo lado. ¿Qué par craneal está comprometido?", o:["XIX","V","VII","VIII"], c:2, e:"La otitis media crónica puede erosionar el canal óseo del nervio facial (VII par), que atraviesa el oído medio, causando parálisis facial periférica ipsilateral."},
{ex:"2025-B", n:35, area:"MED", tema:"Vejiga hiperactiva", q:"Mujer de 68 años, pérdida involuntaria de orina, no logra llegar al baño. Urodinamia: vejiga hiperactiva. ¿Qué grupo farmacológico ayudaría a mejorar sus síntomas?", o:["Antagonistas muscarinicos","Antagonistas de los conductos de Ca","Antagonistas alfa adrenérgicos","Diuréticos tiazídicos"], c:0, e:"Los antimuscarínicos (ej. oxibutinina, tolterodina) reducen las contracciones involuntarias del detrusor y son de primera línea en la vejiga hiperactiva/incontinencia de urgencia."},
{ex:"2025-B", n:36, area:"PED", tema:"Sepsis neonatal precoz", q:"Recién nacido de 35 semanas, parto cesárea de emergencia por gestante febril y sufrimiento fetal agudo, APGAR bajo, taquicárdico, taquipneico, inestabilidad térmica y sensorio alternante. ¿Cuál es el tratamiento antimicrobiano empírico inicial?", o:["Piperacilina/Tazobactam + Amikacina","Ampicilina + Gentamicina","Ampicilina + Ceftriaxona","Meropenem"], c:1, e:"El esquema empírico estándar para sepsis neonatal precoz (corioamnionitis materna, primeras 72 horas) es ampicilina + gentamicina, cubriendo Streptococcus del grupo B y E. coli."},
{ex:"2025-B", n:37, area:"MED", tema:"Fibrilación auricular - control de frecuencia", q:"Varón de 55 años, hipertenso, palpitaciones y disnea. FC 138X'; ritmo irregular con complejos angostos. Ecocardiografía: FEVI 38% (reducida). Para el control de frecuencia, ¿cuál es el medicamento indicado?", o:["Propafenona","Verapamilo","Diltiazem","Digoxina"], c:3, e:"En fibrilación auricular con FEVI reducida (insuficiencia cardiaca), los calcioantagonistas no dihidropiridínicos (verapamilo, diltiazem) están contraindicados por su efecto inotrópico negativo; la digoxina es la opción segura para control de frecuencia."},
{ex:"2025-B", n:38, area:"MED", tema:"Tormenta tiroidea - manejo de la fiebre", q:"Mujer de 56 años, enfermedad de Graves sin tratamiento, fiebre, palpitaciones, diarrea, insomnio. Proptosis, bocio grado II. TSH <0.01, T4 libre 6.0. Cumple diagnóstico de tormenta tiroidea. Respecto al manejo de la fiebre, ¿qué medicamento debe utilizarse?", o:["Aspirina","Paracetamol","Naproxeno","Metamizol"], c:1, e:"En la tormenta tiroidea se debe evitar la aspirina (desplaza la T4 de las proteínas transportadoras y aumenta la hormona libre); el paracetamol es el antipirético seguro."},
{ex:"2025-B", n:39, area:"MED", tema:"Síndrome nefrótico - fisiopatología del edema", q:"En el edema del síndrome nefrótico, una teoría es la expansión de volumen por retención renal primaria de sodio, con factores intrarrenales a través del coeficiente de filtración glomerular y activación de transportadores de sodio en el túbulo colector. ¿A qué se debe esto?", o:["Aumento de electronegatividad de la barrera de filtración","Disminución de la filtración de las proteasas","Incremento de la presión oncótica plasmática","Activación del canal epitelial de sodio y de la bomba Na+/K+-ATPasa"], c:3, e:"La teoría del 'overflow' del síndrome nefrótico propone activación directa del canal epitelial de sodio (ENaC) y de la Na/K-ATPasa en el túbulo colector, causando retención renal primaria de sodio independiente de la hipoalbuminemia."},
{ex:"2025-B", n:40, area:"MED", tema:"Interacciones de la levodopa", q:"En cuanto a las interacciones farmacológicas de la levodopa, ¿cuál es el medicamento que incrementa su metabolismo extracerebral y podría evitar su efecto terapéutico al ser administrado en forma conjunta?", o:["Losartán","Piridoxina","Metformina","Bisoprolol"], c:1, e:"La piridoxina (vitamina B6) es cofactor de la dopa-descarboxilasa periférica, aumentando el metabolismo extracerebral de la levodopa y reduciendo su llegada al SNC (por eso se combina con inhibidores de esa enzima como carbidopa)."},
{ex:"2025-B", n:41, area:"PED", tema:"Intoxicación por paracetamol", q:"Mujer de 13 años, cefalea intensa, dolor abdominal difuso, ictericia progresiva. Antecedente de cuadros depresivos sin tratamiento. Bilirrubina total 12 (indirecta 9.5), TGO 1000, TGP 860, TP 14 seg, glucosa 60, urea 80, creatinina 2. ¿Cuál es el fármaco responsable más probable?", o:["Salicilatos","Antidepresivos tricíclicos","Paracetamol","Ibuprofeno"], c:2, e:"Falla hepática fulminante (transaminasas muy elevadas, coagulopatía, hipoglicemia) en una adolescente con antecedente psiquiátrico es el cuadro clásico de intoxicación por paracetamol con fines suicidas."},
{ex:"2025-B", n:42, area:"PED", tema:"Bronquiolitis aguda", q:"Lactante de 4 meses, dificultad respiratoria, tos paroxística que lleva al vómito, irritabilidad y pobre succión desde hace 12 horas. Antecedente de rinorrea y fiebre hace 7 días, hermano con resfrío. FR 52X', SatO2 90%; sibilantes en ambos hemitórax, tirajes. ¿Cuál es el diagnóstico?", o:["Síndrome obstructivo bronquial","Broncomalacia","Bronquitis aguda","Bronquiolitis aguda"], c:3, e:"Primer episodio de dificultad respiratoria con sibilancias en un lactante menor de 6 meses, tras un pródromo catarral, es bronquiolitis aguda (típicamente por VSR)."},
{ex:"2025-B", n:43, area:"CB", tema:"Anatomía - eyaculación", q:"Durante la eyaculación, ¿qué estructura se cierra para prevenir el reflujo de semen hacia la vejiga urinaria?", o:["Músculo detrusor de la vejiga","Músculo compresor de la vejiga","Esfínter interno de la uretra","Esfínter externo de la uretra"], c:2, e:"El esfínter interno de la uretra (cuello vesical) se contrae durante la eyaculación para evitar la eyaculación retrógrada hacia la vejiga."},
{ex:"2025-B", n:44, area:"MED", tema:"Cetoacidosis diabética", q:"Mujer de 35 años, diabética, dolor abdominal y dificultad respiratoria. Glicemia 316 mg/dL; pH 7.26, HCO3 16 mEq/L, betahidroxibutirato presente. ¿Cuál es el diagnóstico?", o:["Estado hiperosmolar","Descompensación simple diabética","Cetoacidosis diabética","Hiperglicemia por estrés"], c:2, e:"Hiperglicemia + acidosis metabólica (pH y HCO3 bajos) + cetonemia confirman cetoacidosis diabética."},
{ex:"2025-B", n:45, area:"CB", tema:"Farmacología - efecto postantibiótico", q:"La actividad inhibidora de los aminoglucósidos que persiste después de que la concentración sérica ha caído por debajo de la CIM, es un fenómeno conocido como...", o:["mínimo índice de excreción","excelente acceso tisular","efecto postantibiótico","mejora susceptibilidad de los agentes infecciosos"], c:2, e:"El efecto postantibiótico es la supresión persistente del crecimiento bacteriano incluso cuando el fármaco cae bajo la CIM; es marcado en aminoglucósidos y permite su dosificación una vez al día."},
{ex:"2025-B", n:46, area:"MED", tema:"Esclerosis sistémica progresiva", q:"Mujer de 45 años, caída de cabello, artralgias, disfagia, dificultad para abrir la boca, fatiga. Rostro inexpresivo sin arrugas. TC pulmonar: compromiso intersticial con vidrio esmerilado. ANA, Ac Anticentrómero y Anti Topoisomerasa positivos. ¿Cuál es el diagnóstico más probable?", o:["Lupus eritematoso sistémico","Esclerosis sistémica progresiva","Dermatopolimiositis","Vasculitis sistémica"], c:1, e:"Microstomía, facies inexpresiva ('en máscara'), disfagia, enfermedad pulmonar intersticial y anticuerpos anticentrómero/antitopoisomerasa (Scl-70) son característicos de esclerosis sistémica."},
{ex:"2025-B", n:47, area:"CIR", tema:"Tromboembolismo pulmonar postoperatorio", q:"Varón de 56 años, postoperado de prótesis de rodilla, disnea súbita, tos, expectoración hemoptoica. FR 32X', FC 120X'; segundo ruido aumentado, cianosis distal. ¿Qué producto de degradación espera encontrar elevado?", o:["TTP","CPK-MB","Dímero D","TP"], c:2, e:"El dímero D, producto de degradación de la fibrina, está elevado en el tromboembolismo pulmonar, sospechado aquí por el contexto postquirúrgico ortopédico (alto riesgo trombótico)."},
{ex:"2025-B", n:48, area:"PED", tema:"Neumonía adquirida en la comunidad", q:"Preescolar de 3 años, desde hace 4 días fiebre, malestar general, dolor torácico, dificultad respiratoria y tos exigente. FR 36X', SatO2 92%, T° 39.5°C. Crepitantes en ambos hemitórax. Leucocitos 20,000/µL, abastonados 850/µL, PCR 7 ng/dL. ¿Cuál es el diagnóstico?", o:["Neumonía adquirida en la comunidad","Bronquiolitis","Bronquitis aguda","Neumonía atípica"], c:0, e:"Fiebre alta, crepitantes, leucocitosis con desviación izquierda y PCR elevada en un preescolar es el cuadro típico de neumonía bacteriana adquirida en la comunidad."},
{ex:"2025-B", n:49, area:"PED", tema:"Adrenarquia prematura", q:"Niña de 6 años, vello púbico y axilar, olor apocrino y lesiones acneiformes. Edad ósea normal, andrógenos normales, velocidad de crecimiento normal. ¿Cuál es el diagnóstico más probable?", o:["Telarca prematura","Hiperplasia suprarenal tardía","Pubertad precoz central","Adrenarquia prematura"], c:3, e:"Vello púbico/axilar aislado con crecimiento y andrógenos normales (sin telarca ni aceleración del crecimiento) corresponde a adrenarquia prematura, una variante benigna."},
{ex:"2025-B", n:50, area:"SP", tema:"Tamizaje de cáncer colorrectal", q:"En un C.S. I-3 con predominio de población adulta mayor, se han incrementado los casos de cáncer de colon y recto, por lo que se programa tamizaje. ¿Cuál es la técnica indicada según marco normativo nacional?", o:["Sigmoidoscopía","Test inmunológico de sangre oculta en heces","Colonoscopía","Colonografía por tomografía computarizada"], c:1, e:"La normativa peruana de tamizaje de cáncer colorrectal en el primer nivel de atención utiliza el test inmunológico de sangre oculta en heces (FIT) como método de cribado poblacional."},
{ex:"2025-B", n:51, area:"PED", tema:"Cetoacidosis diabética pediátrica", q:"Niño de 11 años, dolor abdominal, laxitud, debilidad y pérdida de peso progresivo; desde hace 2 horas vómitos. MEG, deshidratado, sensorio alternante, taquipneico. ¿Cuál es el diagnóstico más probable?", o:["Cetoacidosis diabética","Abdomen agudo quirúrgico","Encefalitis viral","Intoxicación por organofosforados"], c:0, e:"Pérdida de peso progresiva (poliuria/polidipsia no reconocidas), dolor abdominal, deshidratación y taquipnea (respiración de Kussmaul) en un niño es el debut clásico de cetoacidosis diabética."},
{ex:"2025-B", n:52, area:"PED", tema:"Diagnóstico rápido de faringitis estreptocócica", q:"Niño de 8 años, dolor de garganta, fiebre alta, ganglios cervicales palpables. Eritema faríngeo marcado con exudado, adenopatía cervical. ¿Qué examen permitiría acceder al diagnóstico prontamente?", o:["Detección rápida de anticuerpo","Antiestreptolisinas","Cultivo de secreción faríngea","Detección rápida de antígeno"], c:3, e:"La prueba rápida de detección de antígeno estreptocócico da resultados en minutos, permitiendo decisión terapéutica inmediata, a diferencia del cultivo que demora días."},
{ex:"2025-B", n:53, area:"PED", tema:"Displasia del desarrollo de cadera - diagnóstico", q:"¿Cuál es el examen que sirve para confirmar el diagnóstico de displasia del desarrollo de la cadera y debe realizarse del primer al cuarto mes de vida?", o:["Maniobra de Barlow","Radiografía","Ecografía","Maniobra de Ortolani"], c:2, e:"La ecografía de cadera es el estudio de imagen confirmatorio antes de que ocurra la osificación de la cabeza femoral (hasta los 4-6 meses); después de esa edad se prefiere la radiografía."},
{ex:"2025-B", n:54, area:"GIN", tema:"Manejo del embarazo postérmino con cesárea previa", q:"Gestante de 42 semanas, cesareada anterior hace un año, dinámica uterina ausente; tacto vaginal desfavorable; NST reactivo. ¿Cuál es el manejo?", o:["Inducción de parto","Esperar trabajo de parto","Programar para cesárea","Maduración cervical"], c:2, e:"Embarazo postérmino (42 semanas) con cesárea previa reciente y cérvix desfavorable tiene alto riesgo de rotura uterina con inducción; se prefiere programar cesárea electiva."},
{ex:"2025-B", n:55, area:"MED", tema:"Miastenia gravis", q:"Mujer de 56 años, fatigabilidad que empeora con la actividad y mejora con el reposo, dificultad para deglutir y regurgitación nasal. Debilidad proximal y ptosis bipalpebral, ROT presentes. Mejora con fisostigmina 1 mg IM. ¿Cuál es el mecanismo fisiopatológico?", o:["Disminución del número de receptores activos de Ach en la membrana muscular postsináptica","Inhibición de la fosfocinasa de piridoxal","Inhibición de la polimerización de tubulina en microtúbulos","Compromiso de las células de Schwann con lesión de la mielina"], c:0, e:"La miastenia gravis es una enfermedad autoinmune con anticuerpos contra el receptor de acetilcolina postsináptico, reduciendo su número disponible en la placa neuromuscular; la mejoría con anticolinesterásicos (fisostigmina) confirma el diagnóstico."},
{ex:"2025-B", n:56, area:"MED", tema:"Enfermedad cerebrovascular isquémica establecida", q:"Varón de 52 años, hipertenso, hace una hora cefalea y luego déficit focal en hemicuerpo derecho. PA 178/100; hemiplejía derecha. TC cerebral: hipodensidad en cápsula interna izquierda. NIHSS 20. ¿Cuál es la conducta a seguir?", o:["Alteplasa","Nitratos","Antagonistas del receptor P2Y12","Ácido acetil salicílico"], c:3, e:"La TC muestra ya una hipodensidad establecida (signo de infarto no hiperagudo), lo que contraindica la trombolisis; el manejo es antiagregación con ácido acetilsalicílico y control de factores de riesgo."},
{ex:"2025-B", n:57, area:"MED", tema:"Infecciones oportunistas en VIH", q:"Varón de 46 años con inmunodeficiencia sin tratamiento, CD4 en 150/µL. ¿Qué complicación podría presentarse?", o:["Linfoma del SNC","Aspergilosis","Toxoplasmosis","Citomegalovirus"], c:2, e:"Con CD4 entre 100-200/µL, la toxoplasmosis cerebral es una de las infecciones oportunistas características que debe vigilarse (CMV y linfoma SNC ocurren típicamente con CD4 <50-100)."},
{ex:"2025-B", n:58, area:"PED", tema:"Falla cardiaca por cardiopatía congénita", q:"Lactante de 4 meses con comunicación interventricular, dificultad respiratoria y sudoración durante las tomas. Hepatomegalia. ¿Cuál es el tratamiento inicial más adecuado?", o:["Hidroclorotiazida","Dobutamina en infusión continua","Oxígeno de alto flujo","Digoxina y furosemida"], c:3, e:"En la insuficiencia cardiaca por cortocircuito izquierda-derecha (CIV grande), el manejo médico inicial estándar combina diurético (furosemida) e inotrópico (digoxina)."},
{ex:"2025-B", n:59, area:"MED", tema:"Insuficiencia suprarrenal secundaria a TB", q:"Mujer de 40 años con TB pulmonar tratamiento incompleto, astenia, náusea y vómitos posprandiales desde hace 2 meses. PA 80/50; palidez y pigmentación cutánea. ¿Qué resultado de laboratorio es necesario para concluir el diagnóstico?", o:["Hipocreatinemia","Hiponatremia","Hiperglicemia","Hipopotasemia"], c:1, e:"La insuficiencia suprarrenal (Addison, aquí secundaria a TB adrenal) cursa clásicamente con hiponatremia e hiperpotasemia por déficit de aldosterona y cortisol."},
{ex:"2025-B", n:60, area:"PED", tema:"Definición de anemia en el lactante", q:"Según la norma técnica de salud del Perú, ¿cuál es el valor de hemoglobina en g/dL, a nivel del mar, que define la anemia en un lactante de 6 a 23 meses?", o:["11","10.5","9.5","10"], c:0, e:"La NTS de anemia del MINSA define anemia en niños de 6 a 59 meses (a nivel del mar) como hemoglobina menor a 11 g/dL."},
{ex:"2025-B", n:61, area:"PED", tema:"Meningitis tuberculosa", q:"Niña de 8 años, desde hace 15 días cefalea, somnolencia e irritabilidad; hace 4 días cambios de conducta; 3 días antes vómitos, visión doble y dificultad para hablar. Glasgow 12, discreta rigidez de nuca. TC: discreta hidrocefalia. ¿Cuál es el diagnóstico más probable?", o:["Meningoencefalitis TB","Encefalitis viral","Encefalitis autoinmune","Meningitis bacteriana"], c:0, e:"El curso subagudo (semanas), con compromiso de pares craneales e hidrocefalia, es característico de la meningitis tuberculosa, a diferencia de la meningitis bacteriana (curso agudo, horas)."},
{ex:"2025-B", n:62, area:"GIN", tema:"Hemorragia postparto - causa traumática", q:"Mujer de 35 años, mareo en el posparto inmediato. PA 70/40, FC 110X'; útero contraído a nivel de cicatriz umbilical; sangrado genital abundante. Luego de fluidoterapia, ¿cuál es el paso a seguir?", o:["Aplicación de misoprostol","Revisión de cérvix y vagina","Masaje uterino","Aplicación de oxitócicos"], c:1, e:"Con el útero ya bien contraído (descartando atonía), el sangrado persistente obliga a buscar una causa traumática: revisar cérvix y vagina en busca de desgarros."},
{ex:"2025-B", n:63, area:"PED", tema:"Intoxicación por barbitúricos", q:"Adolescente de 13 años, ataxia, mareos, diplopía y depresión. Antecedente de epilepsia en tratamiento con fenobarbital; hace dos horas tomó varias tabletas con fines suicidas. ¿Cuál es el tratamiento indicado?", o:["Hemodiálisis","Jarabe de ipecacuana","Carbón vegetal activado","Lavado gástrico"], c:2, e:"Dentro de las primeras horas de una sobredosis oral, el carbón activado es el tratamiento de descontaminación gastrointestinal de elección (el jarabe de ipecacuana ya no se recomienda)."},
{ex:"2025-B", n:64, area:"PED", tema:"Enterocolitis necrotizante", q:"RN prematuro de 10 días, en UCIN, distensión abdominal, irritabilidad, náusea, vómito bilioso, letargo e intolerancia alimentaria. Abdomen distendido y doloroso, residuo gástrico bilioso. Rx: neumatosis intestinal. ¿Cuál es el diagnóstico?", o:["Obstrucción intestinal","Enterocolitis necrotizante","Sepsis neonatal","Colitis alérgica"], c:1, e:"La neumatosis intestinal (aire en la pared intestinal) en un prematuro con intolerancia alimentaria y distensión es diagnóstica de enterocolitis necrotizante."},
{ex:"2025-B", n:65, area:"PED", tema:"Erosión corneal", q:"Niño de 9 años, erosión corneal superficial con dolor, lagrimeo y fotofobia. ¿Cuál es el procedimiento inicial para detectar la lesión?", o:["Oftalmoscopio con filtro azul","Instilar fluoresceína","Lámpara de Wood","Lámpara de hendidura"], c:1, e:"La tinción con fluoresceína, examinada con luz azul cobalto, resalta las erosiones/defectos del epitelio corneal, siendo el método inicial más práctico para detectarlas."},
{ex:"2025-B", n:66, area:"MED", tema:"Toxicidad de ciclofosfamida", q:"Paciente con linfoma, va a recibir quimioterapia con ciclofosfamida. ¿Cuál es el efecto adverso de este fármaco?", o:["Hemorragia alveolar","Prolongación del QT corregido","Cistitis hemorrágica","Leucoencefalopatía tardía"], c:2, e:"La ciclofosfamida se metaboliza a acroleína, tóxica para el urotelio, causando cistitis hemorrágica (se previene con mesna e hidratación)."},
{ex:"2025-B", n:67, area:"PED", tema:"Maltrato infantil - hematoma subdural", q:"Lactante de 18 meses, vómitos e hipoactividad desde hace 4 días; padre refiere caída de cuna hace 6 días. Irritable, sin lesiones externas. TC: hematoma subdural laminar extenso sin efecto de masa. Ante sospecha de maltrato infantil, ¿qué examen se debe solicitar?", o:["EEG","Resonancia magnética","Fondo de ojo","Perfil de coagulación"], c:2, e:"Ante sospecha de traumatismo craneal no accidental (síndrome del niño sacudido), el fondo de ojo para buscar hemorragias retinianas es un examen clave de apoyo diagnóstico."},
{ex:"2025-B", n:68, area:"CIR", tema:"Rotura del tendón de Aquiles", q:"Varón de 40 años, al subir escaleras dolor súbito y progresivo en el talón derecho, chasquido audible y dificultad para levantar el pie al caminar. Uso de corticoides. Déficit de flexión plantar, equímosis, signo del hachazo (+) y Simmonds-Thompson (+). ¿Cuál es el diagnóstico?", o:["Luxación de la articulación de tobillo","Fractura de astrágalo","Rotura del tendón de Aquiles","Fractura del calcáneo"], c:2, e:"Chasquido audible, signo del hachazo (depresión palpable) y prueba de Thompson positiva (sin flexión plantar al comprimir la pantorrilla) confirman rotura del tendón de Aquiles, favorecida por el uso de corticoides."},
{ex:"2025-B", n:69, area:"SP", tema:"Gestión en salud - cobertura de vacunación", q:"En un C.S. I-4, de 700 nacidos vivos, 75% fueron vacunados con BCG y HvB de RN (logro esperado ≥95%); no hubo problemas de suministro. ¿Qué acción se debe priorizar?", o:["Cambiar el indicador de logro","Promover la participación intersectorial","Corregir las estrategias para vacunación del RN","Promover el análisis normativo del esquema"], c:2, e:"Al no haber problema de abastecimiento pero sí una brecha grande de cobertura, el problema radica en la estrategia operativa de captación/vacunación del recién nacido, que debe corregirse."},
{ex:"2025-B", n:70, area:"CB", tema:"Anatomía - músculos de la espalda", q:"Varón de 37 años, accidente de tránsito, dolor intenso en la parte posterior del tórax que dificulta la extensión de las articulaciones vertebrales torácicas. ¿Qué músculo está comprometido?", o:["Recto del abdomen","Erector de la columna","Piramidal del abdomen","Pectoral mayor"], c:1, e:"El músculo erector de la columna es el principal extensor de la columna vertebral torácica; su lesión explica el dolor y la dificultad para la extensión."},
{ex:"2025-B", n:71, area:"PED", tema:"Artritis reactiva", q:"Preescolar de 3 años, claudicación intermitente y dolor de cadera derecha desde hace 2 días, sin fiebre ni trauma. Antecedente de diarrea hace 2 semanas. Dolor a la movilidad de cadera, aumento de volumen en talón y tobillo izquierdos. Hemograma y VSG normales; PCR 5 ng/dL. ¿Cuál es el diagnóstico más probable?", o:["Artritis séptica","Fiebre reumática","Artritis reactiva","Artritis postestreptocócica"], c:2, e:"Artritis de varias articulaciones tras un episodio diarreico reciente, con marcadores inflamatorios prácticamente normales (en contra de artritis séptica), es característico de artritis reactiva postinfecciosa."},
{ex:"2025-B", n:72, area:"GIN", tema:"Síndrome de ovario poliquístico - manejo de fertilidad", q:"Mujer de 28 años, irregularidad menstrual y dismenorrea; desea gestar. IMC 37; acantosis nigricans e hirsutismo. Ecografía: ovarios poliquísticos. ¿Cuál es el manejo inicial para lograr gestación?", o:["Pérdida de peso","Histerosalpingografía","Laparoscopía diagnóstica","Citrato de clomifeno"], c:0, e:"En SOP con obesidad marcada, la pérdida de peso es la intervención de primera línea antes de recurrir a inductores de la ovulación, ya que mejora la resistencia a la insulina y puede restaurar la ovulación espontánea."},
{ex:"2025-B", n:73, area:"MED", tema:"Mesotelioma pleural", q:"Minero jubilado de 67 años, dolor pleurítico en hemitórax derecho y disnea. TC pulmonar: engrosamiento pleural, opacidad homogénea basal y retracción del hemitórax derecho. ¿Cuál es el diagnóstico más probable?", o:["Tuberculosis pleural","Derrame paraneumónico","Mesotelioma","Adenocarcinoma"], c:2, e:"Antecedente de exposición ocupacional (minería, asbesto) con engrosamiento pleural y retracción del hemitórax es característico de mesotelioma pleural maligno."},
{ex:"2025-B", n:74, area:"MED", tema:"Tormenta tiroidea - bloqueo de liberación hormonal", q:"En el manejo de la tormenta tiroidea, ¿qué medicamento se encarga de bloquear la liberación de las hormonas tiroideas preformadas?", o:["Yoduro de potasio","Metimazol","Propiltiouracilo","Hidrocortisona"], c:0, e:"El yoduro de potasio (solución de Lugol) bloquea agudamente la liberación de hormona tiroidea preformada (efecto Wolff-Chaikoff); debe administrarse después de las tionamidas para evitar que sea usado como sustrato."},
{ex:"2025-B", n:75, area:"CB", tema:"Farmacocinética de la lidocaína", q:"¿Cuál es la duración en minutos de la acción anestésica local de la lidocaína?", o:["120-180","360-460","60-80","180-360"], c:2, e:"La lidocaína sin vasoconstrictor tiene una duración de acción corta, aproximadamente 60-80 minutos."},
{ex:"2025-B", n:76, area:"CIR", tema:"Fractura de diáfisis humeral", q:"Varón de 25 años, accidente en moto, dolor en región humeral izquierda. Estable, hematoma en tercio medio del brazo, motilidad conservada, pulso radial presente. Rx: fractura de diáfisis humeral con alineación aceptable. ¿Cuál es el tratamiento indicado?", o:["Férula de coaptación","Placas de compresión","Fijación externa","Ortesis funcional"], c:0, e:"Una fractura diafisaria humeral estable, sin compromiso neurovascular y con alineación aceptable, se maneja conservadoramente con férula de coaptación (en U)."},
{ex:"2025-B", n:77, area:"PED", tema:"Sepsis neonatal tardía con compromiso del SNC", q:"RN a término de 20 días, decaído y con pobre succión desde hace 3 días; desviación persistente de la mirada. Madre con ITU en el tercer trimestre. FC 170X', FR 60X', T° 38°C, poco reactivo, sin dificultad respiratoria. ¿Cuál es la terapia empírica de primera línea?", o:["Vancomicina + cefepima","Meropenem + vancomicina","Ampicilina + cefotaxima","Ampicilina + gentamicina"], c:2, e:"La sepsis neonatal tardía con sospecha de compromiso meníngeo (desviación de mirada, mal estado) se cubre empíricamente con ampicilina + cefotaxima, que logran buena penetración en el SNC."},
{ex:"2025-B", n:78, area:"MED", tema:"Miringitis bullosa", q:"Varón de 20 años, dolor y secreción serohemática en oído derecho desde hace 2 días. Otoscopía: tímpano con vesículas de contenido hemorrágico. ¿Cuál es el diagnóstico?", o:["Miringitis bullosa","Pericondritis","Otitis externa maligna","Otomicosis"], c:0, e:"Las vesículas hemorrágicas sobre el tímpano son características de la miringitis bullosa, frecuentemente asociada a infección por Mycoplasma pneumoniae."},
{ex:"2025-B", n:79, area:"GIN", tema:"Anticoncepción postaborto", q:"Mujer de 28 años, se le realizará aspiración manual endouterina por aborto espontáneo incompleto. Desea colocarse DIU de cobre. ¿Cuál es el mejor momento para colocarlo?", o:["Inmediatamente después del procedimiento","Dos semanas posterior al procedimiento","Diferir su uso hasta por un año","En el inicio de su próxima catamenia"], c:0, e:"La inserción inmediata post-aborto del DIU es segura, eficaz y reduce la pérdida de seguimiento; es el momento recomendado por la evidencia y las guías actuales."},
{ex:"2025-B", n:80, area:"MED", tema:"Ascitis - gradiente de albúmina", q:"Mujer de 63 años, diabética, dolor y distensión abdominal, baja de peso y fiebre desde hace 2 meses. Abdomen distendido con matidez desplazable. Paracentesis: gradiente de albúmina suero-líquido de 0.9 g/dL (bajo). ¿Cuál es el diagnóstico más probable?", o:["Insuficiencia cardiaca","Síndrome de Meigs","Artritis reumatoide","Trombosis vena porta"], c:1, e:"Un gradiente de albúmina suero-ascitis (GASA) menor a 1.1 g/dL indica ascitis exudativa, no relacionada a hipertensión portal; entre las opciones, el síndrome de Meigs es la causa clásica de ascitis con GASA bajo asociada a tumor pélvico."},
{ex:"2025-B", n:81, area:"MED", tema:"Tendinopatía por quinolonas", q:"Varón de 65 años, dolor intenso en la parte posterior del tobillo, talón y pantorrilla, imposibilidad para la bipedestación y caminar; sensación de talón hundido. Tratamiento prolongado con antibiótico por cuadro diarreico. ¿Cuál es el fármaco que produce este evento adverso?", o:["Aminoglucósidos","Cefalosporinas","Quinolonas","Sulfamidas"], c:2, e:"Las fluoroquinolonas tienen una asociación bien reconocida con tendinopatía y rotura del tendón de Aquiles, especialmente en adultos mayores."},
{ex:"2025-B", n:82, area:"GIN", tema:"Síndrome de Asherman", q:"Mujer de 27 años, amenorrea de seis meses, sin antecedentes de importancia. FSH, LH, prolactina y TSH normales. TC de hipófisis normal. Se indican anticonceptivos orales combinados y a pesar de ello no presenta menstruación. ¿Cuál es el diagnóstico más probable?", o:["Síndrome de ovario poliquístico","Síndrome de Asherman","Amenorrea hipotalámica","Falla ovárica prematura"], c:1, e:"La ausencia de sangrado por deprivación pese a hormonas normales y estimulación con estrógeno-progestágeno (prueba de progesterona/estrógeno negativa) sugiere una causa uterina: adherencias intrauterinas (síndrome de Asherman)."},
{ex:"2025-B", n:83, area:"SP", tema:"Tasa de letalidad", q:"La región 'A' tiene 500,000 habitantes; durante el 2024 se produjeron 50 casos de dengue de los cuales 5 fallecieron. ¿Cuál fue la tasa de letalidad por dengue en el 2024?", o:["1.0","0.1","10","0.001"], c:2, e:"Tasa de letalidad = (fallecidos/casos) x 100 = (5/50) x 100 = 10%."},
{ex:"2025-B", n:84, area:"MED", tema:"Nódulo tiroideo", q:"Mujer de 30 años, tumoración cervical que aumenta de tamaño progresivamente, asintomática. Nódulo en lóbulo derecho de tiroides 1.5x1.5 cm, indoloro; sin ganglios cervicales. Función tiroidea normal. ¿Qué examen auxiliar solicita de inicio?", o:["Ecografía","Biopsia","Tomografía","Gammagrafía"], c:0, e:"Ante todo nódulo tiroideo palpable, el primer estudio es la ecografía, que determina las características de riesgo del nódulo y guía la necesidad de biopsia por aspiración."},
{ex:"2025-B", n:85, area:"PED", tema:"Triángulo de evaluación pediátrica - shock", q:"Niño de 11 años, 5 días con vómitos y diarrea, 4 días con fiebre, lesiones en piel y dificultad para la marcha; 24 horas antes dolor e inflamación articular, escleras amarillas y oliguria. T° 38.4°C, FC 124X', FR 38X', PA 70/40, SatO2 91%, relleno capilar 3''. Piel ictérica, petequias, púrpura en talones, exantema, sensorio alternante. Según el triángulo de evaluación pediátrica, ¿cuál es el nivel de prioridad?", o:["II","III","I","IV"], c:2, e:"Hipotensión, mal relleno capilar y alteración del sensorio indican un paciente en shock descompensado: máxima prioridad (nivel I, atención inmediata)."},
{ex:"2025-B", n:86, area:"MED", tema:"Hipomagnesemia por inhibidores de bomba de protones", q:"Varón de 62 años, úlcera péptica, usuario crónico de omeprazol; hace 2 días diarreas acuosas abundantes, vómitos, temblor, debilidad muscular y ataxia. PA 80/40, frialdad, palidez. EKG: prolongación de PR y QT, aplanamiento de ondas P, rectificación del ST. ¿Qué trastorno presenta el paciente?", o:["Hipomagnesemia","Hiponatremia","Hipofosfatemia","Hipocalcemia"], c:0, e:"El uso crónico de IBP se asocia a hipomagnesemia, que se manifiesta con temblor, debilidad, ataxia y alteraciones electrocardiográficas como las descritas, agravada aquí por las pérdidas digestivas."},
{ex:"2025-B", n:87, area:"CIR", tema:"Fractura de LeFort III", q:"¿Qué estructuras óseas compromete la fractura LeFort III?", o:["Septum nasal, esfenoides y cóndilo mandibular","Nasal, lacrimal, malar y maxilar superior","Maxilar inferior, arco cigomático y vómer","Lámina cribosa, membrana papirácea y vómer"], c:1, e:"La fractura de LeFort III (disyunción craneofacial completa) separa el macizo facial de la base del cráneo, comprometiendo los huesos nasal, lacrimal, malar (cigomático) y maxilar superior."},
{ex:"2025-B", n:88, area:"CIR", tema:"Fractura de escafoides desplazada", q:"Mujer de 25 años, caída con la mano en extensión hace 2 horas. Dolor a la palpación de la tabaquera anatómica. Rx: segmento del escafoides desplazado más de 1 mm y fractura del primer metacarpiano. ¿Cuál es el tratamiento indicado?", o:["Fijación externa","Intervención quirúrgica","Férula de yeso por 4 semanas","Yeso braquipalmar por 8 semanas"], c:1, e:"Una fractura de escafoides desplazada más de 1 mm tiene alto riesgo de no unión/necrosis avascular por su vascularización retrógrada, por lo que requiere fijación quirúrgica (tornillo)."},
{ex:"2025-B", n:89, area:"GIN", tema:"Hiperplasia endometrial con atipia", q:"Mujer de 42 años, G4P4, hipermenorrea y cansancio. TV normal. Ecografía: útero 7 cm con endometrio de 22 mm. Biopsia endometrial: hiperplasia endometrial con atipia. ¿Cuál es la conducta más adecuada?", o:["DIU con levonorgestrel","Medroxiprogesterona","Repetir biopsia en 3 meses","Histerectomía total"], c:3, e:"La hiperplasia endometrial CON atipia tiene alto riesgo de progresión/coexistencia con cáncer de endometrio; en una mujer con paridad satisfecha, la histerectomía total es el tratamiento definitivo recomendado."},
{ex:"2025-B", n:90, area:"PED", tema:"Convulsión febril simple", q:"Lactante de 18 meses, convulsión generalizada tónico-clónica de 3 minutos con fiebre. Sin antecedentes neurológicos, desarrollo normal. T° 38.5°C; post ictal, despierto; neurológico normal. ¿Cuál es la conducta más adecuada después de controlar la fiebre?", o:["Solicitar resonancia magnética cerebral","Alta domiciliaria sin pruebas complementarias","Administrar tratamiento con lorazepam endovenoso","Realizar punción lumbar"], c:1, e:"Una convulsión febril simple (generalizada, <15 minutos, examen neurológico normal tras el episodio) no requiere estudios complementarios; el alta con indicaciones a la familia es la conducta adecuada."},
{ex:"2025-B", n:91, area:"MED", tema:"Falla cardiaca con FEVI reducida - SGLT2", q:"En pacientes con falla cardiaca y fibrilación auricular con FEVI reducida, ¿qué medicamento está indicado para evitar hospitalización por IC y muerte cardiovascular?", o:["Furosemida","Dapaglifozina","Verapamilo","Atenolol"], c:1, e:"Los inhibidores de SGLT2 (dapagliflozina, empagliflozina) han demostrado reducir la hospitalización por insuficiencia cardiaca y la mortalidad cardiovascular en pacientes con FEVI reducida, independientemente de si son diabéticos."},
{ex:"2025-B", n:92, area:"CB", tema:"Embriología - cierre del tubo neural", q:"¿En qué región se inicia el cierre del tubo neural?", o:["Torácica","Craneal","Cervical","Caudal"], c:2, e:"El cierre del tubo neural comienza en la región cervical (a nivel de los somitas 4-6) y avanza bidireccionalmente hacia el extremo craneal y el caudal."},
{ex:"2025-B", n:93, area:"PED", tema:"Reanimación cardiopulmonar pediátrica", q:"Lactante de 18 meses, paro cardiorrespiratorio por aspiración de alimento. Se realiza RCP básico, ritmo compatible con asistolia en el monitor. ¿Cuál es la indicación farmacológica inicial más apropiada?", o:["Amiodarona","Expansores de volumen","Atropina","Adrenalina"], c:3, e:"La adrenalina es el fármaco de primera línea en asistolia/AESP tanto en RCP pediátrico como en adultos, administrada cada 3-5 minutos durante la reanimación."},
{ex:"2025-B", n:94, area:"MED", tema:"Cirrosis biliar primaria", q:"Mujer de 45 años, desde hace 2 meses astenia, prurito generalizado nocturno y leve ictericia. Hiperpigmentación cutánea, hepatomegalia y esplenomegalia. FA y GGTP 4 veces el valor normal, anticuerpos antimitocondriales positivos, ANA negativo. ¿Cuál es el diagnóstico más probable?", o:["Cirrosis biliar primaria","Hepatitis autoinmune","Colangitis autoinmunitaria","Colangitis esclerosante primaria"], c:0, e:"Prurito, patrón colestásico (FA/GGT elevadas) y anticuerpos antimitocondriales positivos son diagnósticos de cirrosis biliar primaria (colangitis biliar primaria)."},
{ex:"2025-B", n:95, area:"MED", tema:"Disfagia orofaríngea post-ACV", q:"Mujer de 58 años, hipertensa no controlada, infarto cerebral. Hemiparesia izquierda, sialorrea, retiene los alimentos en la boca. ¿Cuál es el tipo de disfagia?", o:["Estructural","Faríngea","Bucal","Esofágica"], c:2, e:"La retención del bolo alimenticio en la boca (dificultad para iniciar la deglución) corresponde a la fase oral/bucal de la disfagia, frecuente tras un ACV con compromiso de la musculatura orofacial."},
{ex:"2025-B", n:96, area:"MED", tema:"Insuficiencia cardiaca descompensada", q:"Varón de 59 años, hipertenso, fibrilador y con falla cardiaca, edema de miembros inferiores y disnea progresiva. PA 152/90, FC 128X'; edema hasta muslos; crepitantes gruesos; RC arrítmicos. Rx: congestión pulmonar. ¿Cuál es el primer paso a seguir con respecto al manejo médico?", o:["Amiodarona","Furosemida","Espironolactona","Labetalol"], c:1, e:"En la insuficiencia cardiaca descompensada con sobrecarga de volumen (edema, congestión pulmonar), el diurético de asa (furosemida) es la primera medida terapéutica para aliviar la congestión."},
{ex:"2025-B", n:97, area:"SP", tema:"Interculturalidad en salud", q:"El médico SERUMS de un C.S. I-2 en comunidad étnica amazónica con baja cobertura de control prenatal, realiza charlas con líderes comunales; las gestantes son multíparas atendidas por parteras y solo hablan el idioma de la etnia. ¿Cuál de las siguientes acciones deberá priorizar?", o:["Capacitar a los líderes para atención del parto","Asegurar la presencia de un intérprete","Uso obligatorio de métodos anticonceptivos","Promover atención exclusiva por parteras"], c:1, e:"La principal barrera identificada es la comunicación (idioma); asegurar un intérprete es la acción prioritaria para mejorar el acceso real a los servicios de salud materna con enfoque intercultural."},
{ex:"2025-B", n:98, area:"GIN", tema:"Clasificación FIGO de miomas", q:"Mujer de 33 años, hipermenorrea desde hace un año. Útero de 7 cm, masa cervical de 3 cm. Ecografía transvaginal: mioma cervical en labio anterior de 28 mm. Según la clasificación FIGO, ¿a qué tipo de mioma pertenece?", o:["8","0","7","1"], c:0, e:"Los miomas en localizaciones distintas al cuerpo uterino (como el cervical) se clasifican como tipo 8 ('otros') en el sistema FIGO de clasificación de miomas."},
{ex:"2025-B", n:99, area:"GIN", tema:"Sangrado postmenopáusico - endometrio delgado", q:"Mujer de 55 años, hace un mes sangrado uterino de 4 días. FUR hace 5 años. Examen clínico normal. Ecografía transvaginal: útero 7 cm, endometrio de 3 mm, ovarios normales. ¿Cuál es la conducta a seguir?", o:["Histerectomía abdominal","Histeroscopía","Legrado uterino","Observación"], c:3, e:"Un endometrio delgado (menor a 4-5 mm) en el contexto de sangrado postmenopáusico tiene un valor predictivo negativo muy alto para patología maligna, por lo que la observación es razonable."},
{ex:"2025-B", n:100, area:"MED", tema:"Colitis pseudomembranosa", q:"Varón de 48 años, tratado con clindamicina y ceftriaxona por 4 semanas, desde hace 7 días diarreas acuosas en 4 cámaras al día, dolor abdominal y fiebre. Leucocitos 15,000/µL. Colonoscopía: pseudomembranas. ¿Cuál es el tratamiento indicado?", o:["Vancomicina","Furazolidona","Piperacilina","Levofloxacino"], c:0, e:"La colitis pseudomembranosa por Clostridioides difficile, favorecida por el uso prolongado de antibióticos, se trata con vancomicina oral (o fidaxomicina) como primera línea."}
];
